INSERT INTO `buku` (`id`, `kelas_id`, `judul`, `rak_buku_id`, `pengarang`, `penerbit_id`, `jumlah`, `tahun`, `cover`, `deskripsi`, `created_at`, `updated_at`) VALUES
(1, 3, 'Akidah Akhlak', 23, 'Usman, Abdurrahman, Noek Aenul Latifah', 6, 30, '2021', '1782207785_akidah xi.png', 'Buku Siswa Akidah Akhlak untuk kelas XI Madrasah Aliyah yang diterbitkan oleh Kementerian Agama Republik Indonesia pada tahun 2015 dalam rangka implementasi Kurikulum 2013 ini merupakan sebuah dokumen pendidikan komprehensif yang disusun dengan menggunakan pendekatan saintifik—yang mencakup proses mengamati, menanya, mengeksplorasi, mengasosiasi, dan mengkomunikasikan—guna membentuk manusia kāffah yang memiliki keseimbangan antara kecerdasan intelektual dan sosial melalui penyajian materi mendalam yang terbagi ke dalam sepuluh bab untuk dua semester, meliputi pemahaman mendalam tentang ilmu kalam serta aliran-aliran teologi di dalamnya, pembiasaan akhlak terpuji dan upaya menghindari akhlak tercela dalam kehidupan sehari-hari, penerapan adab dalam pergaulan remaja serta takziyah, hingga peneladanan kisah-kisah inspiratif dari para sahabat Nabi dan tokoh Islam seperti Fatimatuzzahra, Uways al-Qarni, Abdurrahman bin Auf, dan Abu Dzar al-Ghifari yang semuanya terangkum dalam satu kesatuan dokumen hidup yang terus dimutakhirkan untuk mendukung proses pembelajaran di lingkungan madrasah.', NULL, '2026-06-23 02:15:22'),
(3, 2, 'Akidah Akhlak', 23, 'Nurul Hidayah', 6, 49, '2021', '1782209403_Screenshot 2026-06-23 175013.png', 'Buku Akidah Akhlak untuk Kelas X Madrasah Aliyah yang disusun oleh Nurul Hidayah dan diterbitkan oleh Kementerian Agama Republik Indonesia pada tahun 2020 sebagai implementasi KMA Nomor 183 Tahun 2019 tentang Kurikulum Pendidikan Agama Islam dan Bahasa Arab pada Madrasah merupakan sumber pembelajaran yang dirancang untuk memperkuat pemahaman akidah serta membentuk akhlak mulia peserta didik melalui pendekatan pembelajaran yang aktif, kontekstual, dan berorientasi pada pengembangan karakter. Materi yang disajikan dalam buku ini mencakup pembahasan tentang upaya menghindari berbagai sifat tercela seperti hubb al-dunya, hasad, ujub, sombong, dan riya’, pemahaman terhadap sifat-sifat Allah dan Asmaul Husna, pentingnya taubat sebagai fondasi perjalanan rohani, adab berbakti kepada orang tua dan guru, penerapan nilai-nilai Islam wasathiyah sebagai rahmatan lil ‘alamin, pengendalian nafsu syahwat dan ghadab, pengembangan sifat-sifat utama seperti hikmah, iffah, syaja’ah, dan ‘adalah, menjauhi perilaku licik, tamak, zalim, serta diskriminasi, hingga pembelajaran mengenai kepedulian sosial melalui adab menjenguk orang sakit dan keteladanan Nabi Luth a.s. Seluruh materi disusun secara sistematis melalui kegiatan mengamati, memahami, berdiskusi, mendalami karakter, dan berlatih sehingga tidak hanya berfungsi sebagai sarana transfer pengetahuan, tetapi juga sebagai media pembentukan kepribadian muslim yang beriman, berakhlak karimah, moderat, bertanggung jawab, serta mampu mengamalkan nilai-nilai Islam dalam kehidupan sehari-hari.', NULL, '2026-06-30 20:24:51'),
(4, 7, 'Akidah Akhlak', 23, 'A. Yusuf Alfi Syahr', 6, 52, '2021', '1782211215_akidah 12.png', 'Buku Siswa Akidah Akhlak untuk Kelas XII Madrasah Aliyah yang diterbitkan oleh Kementerian Agama Republik Indonesia sebagai implementasi KMA Nomor 183 Tahun 2019 merupakan sumber pembelajaran yang dirancang untuk memperkuat keimanan, membentuk akhlak mulia, serta mengembangkan karakter peserta didik sesuai nilai-nilai Islam. Materi dalam buku ini mencakup pemahaman dan pengamalan Al-Asmaul Husna, penerapan sikap tasamuh (toleransi), musawah (persamaan derajat), tawasuth (moderat), dan ukhuwah (persaudaraan), serta upaya menghindari berbagai penyakit hati seperti nifaq, ghadab, dan qaswah al-qalb. Selain itu, buku ini membahas etika pergaulan dalam Islam, keteladanan empat imam mazhab fikih, pengembangan sikap terpuji seperti kerja keras, optimisme, kreativitas, dan kolaborasi, serta bahaya perilaku tercela seperti fitnah, hoaks, namimah, tajassus, dan ghibah. Buku ini juga memperkenalkan nilai-nilai akhlak dalam organisasi dan profesi serta keteladanan tokoh-tokoh Islam Indonesia seperti Kiai Kholil al-Bangkalani, Kiai Hasyim Asy\'ari, dan Kiai Ahmad Dahlan. Melalui pembelajaran yang aktif dan kontekstual, buku ini tidak hanya menjadi sarana penguasaan pengetahuan, tetapi juga membentuk pribadi muslim yang beriman, berakhlak karimah, bertanggung jawab, dan mampu berkontribusi positif dalam kehidupan bermasyarakat, berbangsa, dan bernegara.', NULL, '2026-06-23 02:40:15'),
(5, 7, 'AL Quran Hadist', 23, 'Zainuddin,M, Zakie al-Kaf dan Abdullah', 1, 67, '2021', NULL, 'Buku Al-Qur\'an Hadis Kelas XII yang disusun oleh Zainuddin, M., Zakie Al-Kaf, dan Abdullah serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri** merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik terhadap Al-Qur\'an dan hadis sebagai pedoman utama dalam kehidupan. Buku ini menyajikan berbagai materi yang membahas kandungan ayat-ayat Al-Qur\'an dan hadis Nabi Muhammad saw., baik yang berkaitan dengan keimanan, ibadah, akhlak, maupun kehidupan sosial kemasyarakatan. Melalui pembelajaran yang sistematis, peserta didik diajak untuk memahami makna dan pesan yang terkandung dalam Al-Qur\'an dan hadis, mengembangkan kemampuan membaca, menghafal, menerjemahkan, serta menafsirkan isi kandungannya secara kontekstual. Selain itu, buku ini menekankan pentingnya pengamalan nilai-nilai Islam dalam kehidupan sehari-hari, seperti kejujuran, tanggung jawab, kerja keras, toleransi, dan kepedulian sosial. Dilengkapi dengan berbagai aktivitas pembelajaran, latihan, dan evaluasi, buku ini tidak hanya berfungsi sebagai sarana penguasaan pengetahuan keagamaan, tetapi juga sebagai media pembentukan karakter peserta didik agar menjadi pribadi yang beriman, bertakwa, berakhlak mulia, serta mampu menjadikan Al-Qur\'an dan hadis sebagai landasan dalam berpikir, bersikap, dan bertindak.', NULL, '2026-06-23 03:29:39'),
(6, 3, 'AL Quran Hadist', 23, 'Amiruddin dan Rifa I Muhammad', 1, 118, '2021', NULL, 'Buku Al-Qur\'an Hadis Kelas XI Madrasah Aliyah yang disusun oleh Amiruddin dan Rifa\'i Muhammad serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik terhadap kandungan Al-Qur\'an dan hadis sebagai pedoman hidup umat Islam. Materi yang disajikan dalam buku ini mencakup pembahasan tentang penciptaan manusia dan keikhlasan beribadah, sikap hormat dan patuh kepada orang tua serta guru, upaya menghindari pergaulan bebas dan perbuatan keji, penerapan toleransi dan etika pergaulan, semangat menuntut ilmu dan menyebarkannya kepada sesama, tanggung jawab manusia terhadap keluarga dan masyarakat, kompetisi dalam kebaikan, etos kerja seorang muslim, pemilihan makanan yang halal dan baik, serta pentingnya mensyukuri nikmat Allah Swt. Melalui pembelajaran yang sistematis dan kontekstual, peserta didik diajak untuk memahami, menghayati, dan mengamalkan nilai-nilai yang terkandung dalam ayat-ayat Al-Qur\'an dan hadis dalam kehidupan sehari-hari. Dilengkapi dengan berbagai aktivitas pembelajaran, latihan, refleksi, dan evaluasi, buku ini tidak hanya berfungsi sebagai sarana penguasaan pengetahuan keagamaan, tetapi juga sebagai media pembentukan karakter peserta didik agar menjadi pribadi yang beriman, bertakwa, berakhlak mulia, bertanggung jawab, serta mampu menjadikan Al-Qur\'an dan hadis sebagai landasan dalam berpikir, bersikap, dan bertindak.', NULL, '2026-06-23 03:30:07'),
(7, 3, 'AL Quran Hadist', 23, 'A.Syalabi, Ade Armando, Mahrus Asad dkk', 1, 51, '2021', NULL, 'Buku Al-Qur\'an Hadis Kelas XI Madrasah Aliyah yang disusun oleh A. Syalabi, Ade Armando, Mahrus Asad, dkk. serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik terhadap Al-Qur\'an dan hadis sebagai pedoman utama dalam kehidupan umat Islam. Buku ini menyajikan materi yang mencakup berbagai aspek ajaran Islam, seperti pemahaman kandungan ayat-ayat Al-Qur\'an dan hadis Nabi Muhammad saw., pembentukan akhlak mulia, penguatan keimanan, serta penerapan nilai-nilai Islam dalam kehidupan pribadi, sosial, dan masyarakat. Peserta didik diajak untuk memahami pesan-pesan moral dalam Al-Qur\'an dan hadis, mengembangkan sikap jujur, disiplin, tanggung jawab, toleransi, serta kepedulian sosial melalui pendekatan pembelajaran yang aktif dan kontekstual. Selain itu, buku ini juga dilengkapi dengan aktivitas pembelajaran, latihan, serta evaluasi yang mendorong peserta didik untuk berpikir kritis dan mampu mengamalkan ajaran Islam dalam kehidupan sehari-hari. Dengan demikian, buku ini tidak hanya menjadi sarana penguasaan pengetahuan keagamaan, tetapi juga sebagai media pembentukan karakter peserta didik agar menjadi pribadi yang beriman, bertakwa, berakhlak mulia, serta menjadikan Al-Qur\'an dan hadis sebagai pedoman dalam berpikir, bersikap, dan bertindak.', NULL, '2026-06-23 03:32:30'),
(8, 7, 'AL Quran Hadist', 23, 'Shihab, M.Quraisy Zaidan, Abdul Karim', 1, 92, '2021', NULL, 'Buku Al-Qur\'an Hadis Kelas XII Madrasah Aliyah yang disusun oleh M. Quraish Shihab, Zaidan, Abdul Karim, dkk. serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik terhadap Al-Qur\'an dan hadis sebagai pedoman utama dalam kehidupan umat Islam. Buku ini menyajikan materi yang berfokus pada pemaknaan ayat-ayat Al-Qur\'an dan hadis secara kontekstual, penguatan nilai-nilai akidah, pembentukan akhlak mulia, serta penerapan ajaran Islam dalam kehidupan pribadi, sosial, dan kemasyarakatan. Melalui pendekatan pembelajaran yang sistematis dan reflektif, peserta didik diajak untuk memahami pesan-pesan moral, menumbuhkan sikap religius, jujur, disiplin, tanggung jawab, serta kepedulian sosial dalam kehidupan sehari-hari. Selain itu, buku ini juga dilengkapi dengan berbagai aktivitas pembelajaran, latihan, dan evaluasi yang mendorong peserta didik untuk berpikir kritis, mendalami makna ayat dan hadis, serta mengamalkannya dalam kehidupan nyata. Dengan demikian, buku ini tidak hanya berfungsi sebagai sarana penguasaan pengetahuan keagamaan, tetapi juga sebagai media pembentukan karakter peserta didik agar menjadi pribadi yang beriman, bertakwa, berakhlak mulia, dan menjadikan Al-Qur\'an serta hadis sebagai landasan utama dalam berpikir, bersikap, dan bertindak.', NULL, '2026-06-23 03:34:40'),
(9, 3, 'Bahasa Arab', 23, 'Alijarim Mustafa D.Hidayat.dkk', 1, 213, '2021', NULL, 'Buku Bahasa Arab untuk Kelas XI Madrasah Aliyah yang disusun oleh Alijarim, Mustafa, D. Hidayat, dkk. serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan salah satu sumber pembelajaran yang dirancang untuk membantu peserta didik dalam memahami serta menguasai bahasa Arab secara bertahap dan terstruktur. Buku ini memuat berbagai materi dasar hingga lanjutan yang mencakup keterampilan membaca, menulis, menyimak, dan berbicara dalam bahasa Arab dengan penekanan pada penggunaan bahasa dalam konteks kehidupan sehari-hari maupun keagamaan. Penyajian materi disusun secara komunikatif agar peserta didik lebih mudah memahami struktur bahasa, kosakata, serta pola kalimat yang digunakan dalam percakapan maupun teks keislaman. Selain itu, buku ini juga memberikan latihan-latihan yang mendorong peserta didik untuk aktif berlatih, meningkatkan kemampuan berbahasa, serta membiasakan penggunaan bahasa Arab dalam berbagai situasi pembelajaran. Dengan pendekatan yang sistematis dan kontekstual, buku ini tidak hanya berfungsi sebagai sarana penguasaan bahasa, tetapi juga sebagai media untuk menumbuhkan kemampuan komunikasi, kedisiplinan belajar, serta pemahaman terhadap literatur Islam berbahasa Arab sehingga peserta didik mampu mengembangkan kompetensi bahasa secara optimal.', NULL, '2026-06-23 03:37:22'),
(10, 7, 'Bahasa Arab', 23, 'Devi Aprilyanto, Maskukin, H.D Hidayat', 1, 97, '2021', NULL, 'Buku Bahasa Arab untuk Kelas XII Madrasah Aliyah yang disusun oleh Devi Aprilyanto, Maskukin, dan H.D. Hidayat serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan peserta didik dalam memahami dan menggunakan bahasa Arab secara lebih mendalam dan aplikatif. Buku ini menyajikan materi yang mencakup pengembangan keterampilan berbahasa seperti membaca, menulis, menyimak, dan berbicara dengan penekanan pada pemahaman teks-teks berbahasa Arab, khususnya yang berkaitan dengan konteks kehidupan sehari-hari dan kajian keislaman. Penyajian materi disusun secara sistematis dan komunikatif sehingga memudahkan peserta didik dalam memahami struktur bahasa, memperkaya kosakata, serta menguasai pola kalimat yang lebih kompleks. Selain itu, buku ini juga dilengkapi dengan berbagai latihan dan aktivitas pembelajaran yang mendorong peserta didik untuk aktif berlatih, meningkatkan kemampuan komunikasi, serta membiasakan penggunaan bahasa Arab dalam berbagai situasi. Dengan pendekatan yang kontekstual dan bertahap, buku ini tidak hanya berfungsi sebagai sarana penguasaan bahasa, tetapi juga sebagai media untuk memperkuat keterampilan berbahasa sekaligus mendukung pemahaman terhadap sumber-sumber keislaman berbahasa Arab.', NULL, '2026-06-23 03:39:27'),
(11, 3, 'Bahasa Indonesia', 30, 'Dr.Titik Harsiati, M.Pd', 11, 25, '2021', NULL, 'Buku Bahasa Indonesia untuk Kelas XI Madrasah Aliyah yang ditulis oleh Dr. Titik Harsiati, M.Pd. dan diterbitkan oleh PT Erlangga merupakan buku ajar yang disusun untuk mengembangkan kemampuan berbahasa dan bersastra peserta didik secara menyeluruh. Buku ini memuat berbagai materi yang berfokus pada peningkatan keterampilan menyimak, membaca, berbicara, dan menulis dengan pendekatan pembelajaran berbasis teks yang sesuai dengan kurikulum yang berlaku. Setiap materi disajikan secara bertahap dan kontekstual sehingga membantu peserta didik dalam memahami berbagai jenis teks, seperti teks eksposisi, argumentasi, laporan, dan karya sastra, sekaligus melatih kemampuan berpikir kritis dan analitis. Selain itu, buku ini juga memberikan berbagai aktivitas pembelajaran yang mendorong peserta didik untuk aktif berdiskusi, berlatih menulis, serta mengembangkan kemampuan komunikasi secara efektif dan santun dalam bahasa Indonesia. Dengan penyajian yang sistematis dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana penguasaan materi kebahasaan, tetapi juga sebagai media untuk membentuk kemampuan literasi, kreativitas, dan karakter peserta didik dalam menggunakan bahasa Indonesia secara baik dan benar dalam kehidupan sehari-hari.', NULL, '2026-06-23 03:41:10'),
(12, 3, 'Bahasa Indonesia', 30, 'Hamzah Amir, Anderson Mark and Kathy Anderson dan Coyle.D', 3, 30, '2021', NULL, 'Buku Bahasa Indonesia untuk Kelas XI yang disusun oleh Hamzah Amir, Anderson Mark, Kathy Anderson, dan D. Coyle serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk meningkatkan kompetensi literasi peserta didik melalui berbagai kegiatan membaca, menulis, berbicara, dan menyimak. Materi yang disajikan dalam buku ini mengajak peserta didik untuk memahami beragam jenis teks, mengembangkan kemampuan berpikir kritis, serta mengekspresikan gagasan secara efektif dalam berbagai konteks komunikasi. Melalui pembelajaran yang berorientasi pada keterampilan berbahasa dan apresiasi sastra, peserta didik diajak untuk menganalisis informasi, menginterpretasikan makna, menyusun karya tulis, serta mengembangkan kemampuan berkomunikasi secara santun dan argumentatif. Berbagai contoh, latihan, dan aktivitas yang disajikan membantu peserta didik menerapkan pengetahuan kebahasaan dalam situasi nyata sekaligus memperluas wawasan budaya, sosial, dan akademik. Dengan pendekatan yang interaktif dan kontekstual, buku ini tidak hanya mendukung pencapaian kompetensi bahasa Indonesia, tetapi juga menumbuhkan kreativitas, kepekaan berpikir, serta kemampuan literasi yang diperlukan dalam kehidupan sehari-hari maupun jenjang pendidikan yang lebih tinggi.\r\n', NULL, NULL),
(13, 2, 'Bahasa Indonesia', 4, 'Dr.Titik Harsiati, M.Pd', 11, 40, '2021', NULL, 'Buku Bahasa Indonesia untuk Kelas X yang ditulis oleh Dr. Titik Harsiati, M.Pd. dan diterbitkan oleh PT Erlangga hadir sebagai sarana pembelajaran yang membantu peserta didik mengembangkan kemampuan berbahasa sekaligus memperkuat budaya literasi. Melalui penyajian materi yang sistematis dan mudah dipahami, buku ini mengenalkan berbagai bentuk teks, kaidah kebahasaan, serta teknik berkomunikasi yang efektif dalam berbagai situasi. Peserta didik diajak untuk mengeksplorasi ide, memahami informasi, menyampaikan pendapat secara logis, serta mengapresiasi karya sastra sebagai bagian dari pengembangan wawasan dan karakter. Beragam kegiatan pembelajaran, latihan, dan tugas yang disajikan mendorong peserta didik untuk aktif berpikir, berdiskusi, serta menghasilkan karya tulis yang kreatif dan komunikatif. Dengan mengintegrasikan aspek pengetahuan, keterampilan, dan sikap, buku ini tidak hanya berfungsi sebagai sumber belajar bahasa Indonesia, tetapi juga sebagai media untuk membangun kemampuan berpikir kritis, kreativitas, dan kepercayaan diri dalam berkomunikasi di lingkungan akademik maupun kehidupan sehari-hari.\r\n', NULL, NULL),
(14, 7, 'Bahasa Inggris', 47, 'Irawati,Y, Basthomi Z.Rohmah', 4, 49, '2021', NULL, 'Buku Bahasa Inggris untuk Kelas XII yang disusun oleh Irawati Y., Basthomi, dan Z. Rohmah serta diterbitkan oleh PT Gramedia Pustaka Utama merupakan sumber belajar yang dirancang untuk membantu peserta didik mengembangkan kemampuan berbahasa Inggris secara komprehensif sebagai sarana komunikasi global. Materi yang disajikan dalam buku ini mengintegrasikan keterampilan mendengarkan, berbicara, membaca, dan menulis melalui berbagai tema yang dekat dengan kehidupan akademik maupun sosial peserta didik. Setiap pembahasan dirancang untuk memperkaya kosakata, meningkatkan pemahaman tata bahasa, serta melatih kemampuan berpikir kritis dan menyampaikan gagasan secara efektif dalam bahasa Inggris. Beragam teks, dialog, latihan, dan proyek pembelajaran yang disediakan mendorong peserta didik untuk lebih aktif menggunakan bahasa Inggris dalam berbagai konteks komunikasi, baik lisan maupun tulisan. Dengan pendekatan yang komunikatif dan berorientasi pada praktik, buku ini tidak hanya membantu peserta didik mencapai kompetensi kebahasaan yang diharapkan, tetapi juga mempersiapkan mereka menghadapi tantangan pendidikan lanjutan dan perkembangan dunia global yang semakin menuntut kemampuan berbahasa Inggris yang baik.\r\n', NULL, NULL),
(15, 2, 'Bahasa Inggris', 13, 'Irawati,Y, Basthomi Z.Rohmah', 11, 40, '2022', NULL, 'Buku Bahasa Inggris untuk Kelas X yang disusun oleh Irawati Y., Basthomi, dan Z. Rohmah serta diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk membangun fondasi kemampuan berbahasa Inggris peserta didik pada jenjang pendidikan menengah. Buku ini menyajikan berbagai materi yang berfokus pada pengembangan keterampilan listening, speaking, reading, dan writing melalui topik-topik yang relevan dengan kehidupan sehari-hari, lingkungan sekolah, dan interaksi sosial. Setiap pembelajaran disusun secara bertahap untuk membantu peserta didik memahami kosakata, struktur bahasa, serta cara menggunakan bahasa Inggris secara tepat dalam berbagai situasi komunikasi. Selain dilengkapi dengan beragam latihan, dialog, dan aktivitas interaktif, buku ini juga mendorong peserta didik untuk lebih percaya diri dalam mengungkapkan ide, pendapat, dan pengalaman menggunakan bahasa Inggris. Dengan pendekatan yang komunikatif dan berpusat pada peserta didik, buku ini tidak hanya mendukung pencapaian kompetensi kebahasaan, tetapi juga membantu mengembangkan kemampuan berpikir kritis, kreativitas, dan keterampilan komunikasi yang dibutuhkan dalam era global.\r\n', NULL, NULL),
(16, 3, 'Bahasa Inggris', 46, 'Anderson,L.W, Arnold J Murphey, Gerot L, Guariento,W', 3, 30, '2022', NULL, 'Buku Bahasa Inggris untuk Kelas XI yang disusun oleh Anderson, L.W., Arnold J. Murphey, Gerot, L., dan Guariento, W. serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan peserta didik dalam menggunakan bahasa Inggris secara efektif baik dalam konteks akademik maupun kehidupan sehari-hari. Buku ini menghadirkan berbagai materi yang berfokus pada pengembangan keterampilan membaca, menulis, berbicara, dan menyimak melalui beragam jenis teks dan aktivitas komunikatif yang relevan dengan pengalaman peserta didik. Selain memperluas penguasaan kosakata dan tata bahasa, buku ini juga mendorong peserta didik untuk berpikir kritis, memahami informasi dari berbagai sumber, serta menyampaikan gagasan dan pendapat secara jelas dan terstruktur dalam bahasa Inggris. Berbagai latihan, tugas proyek, dan kegiatan kolaboratif yang disajikan membantu peserta didik mengembangkan kepercayaan diri dalam berkomunikasi sekaligus meningkatkan kemampuan literasi dan pemecahan masalah. Dengan pendekatan pembelajaran yang interaktif dan kontekstual, buku ini tidak hanya mendukung pencapaian kompetensi bahasa Inggris, tetapi juga mempersiapkan peserta didik untuk menghadapi tantangan pendidikan lanjutan dan perkembangan dunia global yang semakin dinamis.\r\n', NULL, NULL),
(17, 7, 'Bahasa Inggris', 47, 'Rohmah,Z, Taylor,E.K, Widiati, M. Williams', 3, 30, '2022', NULL, 'Buku Bahasa Inggris untuk Kelas XII yang disusun oleh Z. Rohmah, E.K. Taylor, M. Widiati, dan Williams serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk mengembangkan kemampuan berbahasa Inggris peserta didik pada tingkat lanjut sekaligus mempersiapkan mereka menghadapi tantangan pendidikan tinggi dan dunia global. Buku ini menyajikan berbagai materi yang mendorong peserta didik untuk memahami, menganalisis, dan menghasilkan beragam jenis teks dalam bahasa Inggris, baik lisan maupun tulisan. Melalui kegiatan pembelajaran yang komunikatif dan berbasis keterampilan, peserta didik diajak untuk meningkatkan kemampuan membaca, menulis, berbicara, dan menyimak secara terpadu, serta mengembangkan kemampuan berpikir kritis, kreativitas, dan pemecahan masalah. Berbagai latihan, proyek, diskusi, dan aktivitas kolaboratif yang disajikan membantu peserta didik menggunakan bahasa Inggris secara aktif dalam konteks akademik maupun kehidupan sehari-hari. Dengan pendekatan yang interaktif dan kontekstual, buku ini tidak hanya berfokus pada penguasaan tata bahasa dan kosakata, tetapi juga membekali peserta didik dengan keterampilan komunikasi yang efektif, kepercayaan diri, serta wawasan yang diperlukan untuk berpartisipasi dalam lingkungan global yang semakin berkembang.\r\n', NULL, NULL),
(18, 2, 'Biologi', 1, 'Budiyono.S, Nugroho.H , Campbell, Hartato.H', 11, 25, '2022', NULL, 'Buku Biologi untuk Kelas X yang ditulis oleh Budiyono S., H. Nugroho, Campbell, dan H. Hartato serta diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperkenalkan konsep-konsep dasar biologi sebagai ilmu yang mempelajari kehidupan dan makhluk hidup. Materi dalam buku ini disajikan secara sistematis, mulai dari ruang lingkup biologi, keanekaragaman hayati, klasifikasi makhluk hidup, struktur dan fungsi sel, hingga berbagai proses kehidupan yang terjadi pada organisme. Melalui pembahasan yang didukung oleh ilustrasi, contoh kasus, kegiatan praktikum, dan latihan soal, peserta didik diajak untuk memahami fenomena biologis secara ilmiah serta mengembangkan keterampilan observasi, analisis, dan pemecahan masalah. Buku ini juga menumbuhkan kesadaran akan pentingnya menjaga lingkungan dan melestarikan keanekaragaman hayati sebagai bagian dari kehidupan. Dengan pendekatan yang mengintegrasikan pengetahuan, keterampilan, dan sikap ilmiah, buku ini tidak hanya membantu peserta didik menguasai konsep-konsep biologi, tetapi juga mendorong mereka untuk berpikir kritis, kreatif, dan peduli terhadap lingkungan serta perkembangan ilmu pengetahuan dan teknologi.\r\n', NULL, NULL),
(19, 3, 'Biologi', 24, 'Dra. Irmaningtyas.M.Pd', 11, 30, '2022', NULL, 'Buku Biologi untuk Kelas XI yang disusun oleh Dra. Irnaningtyas, M.Pd. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik mengenai berbagai konsep biologi yang berkaitan dengan struktur, fungsi, dan proses kehidupan pada makhluk hidup. Buku ini membahas beragam materi penting, seperti sistem organ manusia, jaringan tumbuhan dan hewan, sistem peredaran darah, sistem pencernaan, sistem pernapasan, sistem ekskresi, sistem koordinasi, serta mekanisme reproduksi dan pertahanan tubuh. Setiap materi disajikan dengan bahasa yang jelas dan didukung oleh gambar, diagram, kegiatan praktikum, serta latihan yang membantu peserta didik memahami konsep secara lebih mendalam dan aplikatif. Melalui pendekatan ilmiah, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir kritis, melakukan pengamatan, menganalisis data, dan menarik kesimpulan berdasarkan fakta yang diperoleh. Selain meningkatkan penguasaan konsep biologi, buku ini juga menumbuhkan kesadaran akan pentingnya menjaga kesehatan, lingkungan, dan keseimbangan kehidupan sebagai bagian dari tanggung jawab terhadap diri sendiri dan masyarakat.\r\n', NULL, NULL),
(20, 2, 'Ekonomi', 15, 'Wahyu adji, Suwerti, dan Suratno', 11, 50, '2022', NULL, 'Buku Ekonomi untuk Kelas X yang disusun oleh Wahyu Adji, Suwerli, dan Suratno serta diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai ilmu ekonomi dan perannya dalam kehidupan sehari-hari. Buku ini membahas berbagai konsep fundamental, seperti kebutuhan manusia, kelangkaan sumber daya, pilihan ekonomi, pelaku kegiatan ekonomi, sistem ekonomi, pasar, serta peran lembaga keuangan dalam perekonomian. Materi disajikan secara runtut dan kontekstual sehingga peserta didik dapat menghubungkan teori ekonomi dengan fenomena yang terjadi di lingkungan sekitar. Berbagai contoh kasus, ilustrasi, latihan, dan aktivitas pembelajaran juga disertakan untuk membantu peserta didik mengembangkan kemampuan analisis serta keterampilan dalam memahami permasalahan ekonomi. Melalui pendekatan yang aplikatif, buku ini tidak hanya bertujuan memperluas wawasan ekonomi peserta didik, tetapi juga menumbuhkan sikap rasional, kritis, dan bertanggung jawab dalam mengambil keputusan ekonomi baik sebagai individu maupun sebagai anggota masyarakat.\r\n', NULL, NULL),
(21, 7, 'Ekonomi', 51, 'Wahyu adji, Suwerti, dan Suratno', 11, 50, '2022', NULL, 'Buku Ekonomi untuk Kelas XII yang disusun oleh Wahyu Adji, Suwerli, dan Suratno serta diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperluas pemahaman peserta didik mengenai berbagai konsep ekonomi yang berkaitan dengan perekonomian nasional maupun global. Buku ini membahas berbagai materi penting, seperti pendapatan nasional, pertumbuhan dan pembangunan ekonomi, ketenagakerjaan, inflasi, kebijakan fiskal dan moneter, perdagangan internasional, kerja sama ekonomi antarnegara, serta akuntansi dan manajemen sebagai bagian dari aktivitas ekonomi modern. Penyajian materi dilakukan secara sistematis dan didukung oleh berbagai contoh kasus, data, ilustrasi, serta latihan yang membantu peserta didik memahami hubungan antara teori ekonomi dan realitas yang terjadi di masyarakat. Selain mengembangkan kemampuan analisis terhadap berbagai permasalahan ekonomi, buku ini juga mendorong peserta didik untuk berpikir kritis, logis, dan objektif dalam menilai fenomena ekonomi yang terjadi di tingkat lokal, nasional, maupun internasional. Dengan pendekatan yang kontekstual dan aplikatif, buku ini menjadi sarana pembelajaran yang membantu peserta didik mempersiapkan diri menghadapi tantangan ekonomi di masa depan serta berperan aktif dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(22, 3, 'Ekonomi', 50, 'Baridwan Zaki, Bumol William J and Alan S.Binder, Budiono.Dr dan Ismaya Suyana,SE', 3, 50, '2022', NULL, 'Buku Ekonomi untuk Kelas XI yang disusun oleh Zaki Baridwan, William J. Baumol, Alan S. Blinder, Dr. Boediono, dan Suyana Ismaya, S.E. serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk memperluas wawasan peserta didik mengenai berbagai konsep dan aktivitas ekonomi yang terjadi dalam kehidupan masyarakat. Buku ini mengupas berbagai materi penting, mulai dari perilaku konsumen dan produsen, mekanisme pasar, kebijakan ekonomi, koperasi, perpajakan, hingga peran pemerintah dalam menjaga stabilitas perekonomian. Setiap pembahasan disajikan dengan mengaitkan teori ekonomi dengan fenomena nyata sehingga peserta didik dapat memahami hubungan antara konsep yang dipelajari dengan kondisi ekonomi di lingkungan sekitar. Melalui berbagai contoh, studi kasus, dan aktivitas pembelajaran, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir analitis, mengambil keputusan secara rasional, serta memahami dampak berbagai kebijakan ekonomi terhadap masyarakat. Dengan pendekatan yang aplikatif dan kontekstual, buku ini tidak hanya menjadi sarana untuk mempelajari ilmu ekonomi, tetapi juga membantu membentuk sikap kritis, kreatif, dan bertanggung jawab dalam menghadapi berbagai persoalan ekonomi di era modern.\r\n', NULL, NULL),
(23, 2, 'Ekonomi', 15, 'Alam S', 11, 25, '2022', NULL, 'Buku Ekonomi untuk Kelas X yang ditulis oleh Alam S. dan diterbitkan oleh PT Erlangga merupakan sumber belajar yang memperkenalkan peserta didik pada konsep-konsep dasar ilmu ekonomi serta peranannya dalam kehidupan sehari-hari. Materi yang disajikan membahas berbagai topik penting, seperti kebutuhan manusia, kelangkaan sumber daya, motif dan prinsip ekonomi, kegiatan produksi, distribusi, konsumsi, serta berbagai sistem ekonomi yang diterapkan di dunia. Penyampaian materi dilakukan secara sistematis dengan dukungan ilustrasi, contoh kasus, dan aktivitas pembelajaran yang membantu peserta didik memahami keterkaitan antara teori ekonomi dan fenomena yang terjadi di masyarakat. Selain itu, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir logis, analitis, dan kritis dalam menghadapi berbagai permasalahan ekonomi. Dengan pendekatan yang kontekstual dan mudah dipahami, buku ini tidak hanya berfungsi sebagai sarana pembelajaran ekonomi, tetapi juga membantu peserta didik membangun pemahaman yang lebih baik mengenai pengelolaan sumber daya dan pengambilan keputusan ekonomi secara bijaksana.\r\n', NULL, NULL),
(24, 2, 'Ekonomi', 15, 'Wahyu adji, Suwerti, dan Suratno', 11, 26, '2022', NULL, 'Buku Ekonomi untuk Kelas X yang disusun oleh Wahyu Adji, Suwerli, dan Suratno serta diterbitkan oleh PT Erlangga merupakan bahan ajar yang memberikan pengenalan menyeluruh mengenai konsep-konsep dasar ilmu ekonomi dan penerapannya dalam kehidupan sehari-hari. Melalui pembahasan yang sistematis dan mudah dipahami, buku ini mengajak peserta didik untuk mengenali berbagai permasalahan ekonomi yang muncul akibat keterbatasan sumber daya, memahami kebutuhan manusia, mempelajari prinsip dan motif ekonomi, serta mengenal berbagai kegiatan ekonomi seperti produksi, distribusi, dan konsumsi. Materi yang disajikan juga dilengkapi dengan contoh-contoh nyata, ilustrasi, serta latihan yang membantu peserta didik menghubungkan teori dengan kondisi ekonomi yang terjadi di lingkungan sekitar. Selain memperkaya pengetahuan ekonomi, buku ini mendorong peserta didik untuk berpikir kritis, mengambil keputusan secara rasional, dan memahami peran ekonomi dalam kehidupan individu maupun masyarakat. Dengan pendekatan yang kontekstual dan aplikatif, buku ini menjadi sarana pembelajaran yang efektif untuk membangun pemahaman dasar ekonomi sekaligus menumbuhkan kesadaran dalam mengelola sumber daya secara bijaksana.\r\n', NULL, NULL),
(25, 3, 'Fikih', 23, 'Mahbub, Ma afi dan Marwini, Amiruddin, Khairul umam A.Achyar', 1, 127, '2022', NULL, 'Buku Fikih untuk Kelas XI Madrasah Aliyah yang disusun oleh Mahbub Ma’afi, Marwini, Amiruddin, Khairul Umam, A. Achyar, dan tim penulis lainnya serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang membimbing peserta didik dalam memahami berbagai ketentuan hukum Islam yang berkaitan dengan kehidupan pribadi maupun sosial. Materi yang dibahas mencakup pemahaman mengenai ibadah, muamalah, perkawinan, waris, peradilan Islam, serta berbagai persoalan fikih yang relevan dengan kehidupan masyarakat modern. Penyajian materi dilakukan secara sistematis dengan mengintegrasikan dalil Al-Qur\'an, hadis, pendapat ulama, dan contoh penerapan dalam kehidupan sehari-hari sehingga peserta didik dapat memahami hukum Islam secara lebih komprehensif. Selain memperkuat pengetahuan keagamaan, buku ini juga mendorong peserta didik untuk mengembangkan sikap kritis, tanggung jawab, dan kesadaran dalam menjalankan ajaran Islam sesuai tuntunan syariat. Berbagai latihan, studi kasus, dan kegiatan pembelajaran yang disajikan membantu peserta didik menghubungkan konsep fikih dengan realitas kehidupan sehingga mampu menerapkan nilai-nilai Islam secara bijaksana dan proporsional dalam lingkungan keluarga, sekolah, maupun masyarakat.\r\n', NULL, NULL),
(26, 7, 'Fisika', 27, 'Abbel, Morrison dan Akrill T.G.Bennet Bueche,F.J., Jerden D.A', 11, 30, '2022', NULL, 'Buku Fisika untuk Kelas XII yang disusun oleh Abbel, Morrison, Akrill, T.G. Bennet, F.J. Bueche, dan D.A. Jerden serta diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep-konsep fisika yang lebih kompleks dan aplikatif. Buku ini membahas berbagai materi penting seperti listrik dinamis, medan magnet, induksi elektromagnetik, gelombang elektromagnetik, fisika modern, teori relativitas, hingga gejala-gejala alam yang dapat dijelaskan melalui prinsip-prinsip fisika. Setiap topik disajikan secara sistematis dengan didukung penjelasan konseptual, ilustrasi, contoh soal, eksperimen sederhana, dan latihan yang membantu peserta didik memahami hubungan antara teori dan penerapannya dalam kehidupan sehari-hari. Selain menekankan penguasaan konsep, buku ini juga mendorong pengembangan kemampuan berpikir logis, analitis, dan pemecahan masalah melalui pendekatan ilmiah yang menuntut pengamatan, pengukuran, dan penalaran berdasarkan fakta. Dengan penyajian yang komprehensif dan kontekstual, buku ini tidak hanya menjadi sarana untuk mempelajari ilmu fisika, tetapi juga membantu peserta didik mengembangkan sikap ilmiah dan kesiapan menghadapi jenjang pendidikan yang lebih tinggi di bidang sains dan teknologi.\r\n', NULL, NULL),
(27, 3, 'Fisika', 26, 'Ir.Marthen Kanginan.M.Sc', 11, 30, '2022', NULL, 'Buku Fisika untuk Kelas XI yang ditulis oleh Ir. Marthen Kanginan, M.Sc. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk membantu peserta didik memahami berbagai konsep fisika secara mendalam melalui pendekatan ilmiah dan aplikatif. Buku ini membahas beragam materi penting, seperti gerak harmonik, fluida, kalor dan termodinamika, gelombang, optik, serta berbagai prinsip fisika yang berkaitan dengan fenomena alam dan perkembangan teknologi modern. Setiap topik disajikan secara sistematis dengan dukungan ilustrasi, contoh soal, kegiatan eksperimen, dan latihan yang mendorong peserta didik untuk mengembangkan kemampuan berpikir logis, analitis, dan pemecahan masalah. Selain menekankan penguasaan konsep dan perhitungan, buku ini juga mengaitkan materi fisika dengan penerapannya dalam kehidupan sehari-hari sehingga pembelajaran menjadi lebih kontekstual dan mudah dipahami. Dengan penyajian yang komprehensif dan berorientasi pada pengembangan keterampilan ilmiah, buku ini tidak hanya membantu peserta didik mencapai kompetensi akademik yang diharapkan, tetapi juga menumbuhkan rasa ingin tahu, sikap kritis, dan apresiasi terhadap peran fisika dalam kehidupan manusia.', NULL, '2026-06-24 01:12:19'),
(28, 7, 'Fisika', 27, 'Ir.Marthen Kanginan.M.Sc', 11, 30, '2022', NULL, 'Buku Fisika untuk Kelas XII yang ditulis oleh Ir. Marthen Kanginan, M.Sc. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik terhadap konsep-konsep fisika tingkat lanjut serta penerapannya dalam berbagai fenomena alam dan perkembangan teknologi modern. Buku ini membahas beragam materi penting, seperti listrik statis dan dinamis, medan magnet, induksi elektromagnetik, gelombang elektromagnetik, fisika kuantum, teori relativitas, hingga radioaktivitas yang menjadi dasar bagi berbagai inovasi sains dan teknologi. Setiap materi disajikan secara sistematis dengan dukungan ilustrasi, contoh soal, eksperimen, dan latihan yang membantu peserta didik memahami hubungan antara konsep teoritis dan penerapannya dalam kehidupan nyata. Melalui pendekatan ilmiah yang menekankan pengamatan, analisis, dan pemecahan masalah, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir logis, kritis, dan kreatif. Dengan penyajian yang komprehensif dan kontekstual, buku ini tidak hanya menjadi sarana pembelajaran fisika yang efektif, tetapi juga membantu mempersiapkan peserta didik untuk melanjutkan pendidikan ke jenjang yang lebih tinggi di bidang sains dan teknologi.\r\n', NULL, NULL),
(29, 7, 'Geografi', 39, 'Brata, Nugroho, Trisnu Danang Endarto dkk', 5, 35, '2022', NULL, 'Buku Geografi untuk Kelas XII yang disusun oleh Brata, Nugroho, Trisnu Danang Endarto, dan tim penulis lainnya serta diterbitkan oleh Grafindo Media Pratama merupakan bahan ajar yang dirancang untuk memperluas pemahaman peserta didik mengenai dinamika geosfer dan berbagai fenomena keruangan yang terjadi di tingkat lokal, nasional, maupun global. Materi dalam buku ini membahas berbagai konsep penting, seperti pembangunan wilayah, interaksi antarruang, kerja sama antarnegara, pemanfaatan sumber daya alam, pengelolaan lingkungan hidup, serta berbagai isu geografis yang berkaitan dengan perkembangan masyarakat modern. Penyajian materi didukung oleh peta, ilustrasi, data, studi kasus, dan kegiatan analisis yang membantu peserta didik memahami hubungan antara kondisi fisik wilayah dengan aktivitas manusia. Melalui pendekatan yang kontekstual dan berbasis fenomena nyata, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir spasial, analitis, dan kritis dalam mengkaji berbagai permasalahan geografi. Selain sebagai sumber pengetahuan, buku ini juga berperan dalam menumbuhkan kepedulian terhadap lingkungan serta kesadaran akan pentingnya pembangunan berkelanjutan untuk mendukung kesejahteraan masyarakat dan kelestarian bumi.\r\n', NULL, NULL),
(30, 2, 'Geografi', 8, 'Yasinto Sindhu P', 11, 30, '2022', NULL, 'Buku Geografi untuk Kelas X yang disusun oleh Yasinto Sindhu P. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang memberikan pemahaman dasar mengenai ilmu geografi serta berbagai fenomena yang terjadi di permukaan bumi. Buku ini membahas konsep-konsep fundamental geografi, seperti ruang lingkup geografi, prinsip dan pendekatan geografi, peta, penginderaan jauh, sistem informasi geografis, dinamika litosfer, atmosfer, hidrosfer, dan biosfer, serta interaksi antara manusia dengan lingkungannya. Materi disajikan secara sistematis dengan dukungan ilustrasi, peta, gambar, dan studi kasus yang membantu peserta didik memahami hubungan antara kondisi alam dan aktivitas manusia. Melalui berbagai kegiatan pembelajaran, latihan, dan tugas analisis, peserta didik diajak untuk mengembangkan kemampuan berpikir spasial, kritis, dan analitis dalam mengkaji berbagai permasalahan lingkungan dan kewilayahan. Dengan pendekatan yang kontekstual dan aplikatif, buku ini tidak hanya menjadi sarana untuk menguasai konsep-konsep geografi, tetapi juga menumbuhkan kesadaran akan pentingnya menjaga keseimbangan lingkungan dan memanfaatkan sumber daya alam secara berkelanjutan.\r\n', NULL, NULL),
(31, 3, 'Geografi', 38, 'Yasinto Sindhu P', 11, 30, '2023', NULL, 'Buku Geografi untuk Kelas XI yang disusun oleh Yasinto Sindhu P. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik mengenai berbagai fenomena geografi yang terjadi di permukaan bumi serta interaksinya dengan kehidupan manusia. Buku ini membahas beragam materi penting, seperti kondisi dan persebaran sumber daya alam, kependudukan, lingkungan hidup, pembangunan berkelanjutan, mitigasi bencana, serta pemanfaatan teknologi geospasial dalam kehidupan modern. Materi disajikan secara sistematis dan didukung oleh peta, grafik, ilustrasi, serta studi kasus yang membantu peserta didik memahami keterkaitan antara aspek fisik dan sosial dalam suatu wilayah. Melalui berbagai aktivitas pembelajaran, analisis data, dan latihan soal, peserta didik didorong untuk mengembangkan kemampuan berpikir spasial, kritis, dan analitis dalam mengkaji berbagai permasalahan lingkungan dan kewilayahan. Dengan pendekatan yang kontekstual dan berbasis fenomena nyata, buku ini tidak hanya memperkaya wawasan geografi peserta didik, tetapi juga menumbuhkan kepedulian terhadap lingkungan serta kesadaran akan pentingnya pengelolaan sumber daya secara bijaksana demi tercapainya pembangunan yang berkelanjutan.\r\n', NULL, NULL),
(32, 2, 'Kimia', 3, 'Drs.Unggul Sudarmo, M.Pd', 11, 25, '2023', NULL, 'Buku Kimia untuk Kelas X yang disusun oleh Drs. Unggul Sudarmo, M.Pd. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperkenalkan konsep-konsep dasar kimia sebagai landasan dalam memahami berbagai fenomena alam dan perubahan materi. Buku ini membahas materi-materi penting seperti hakikat ilmu kimia, metode ilmiah, struktur atom, sistem periodik unsur, ikatan kimia, tata nama senyawa, serta perhitungan kimia dasar yang menjadi fondasi bagi pembelajaran kimia pada jenjang berikutnya. Penyajian materi dilakukan secara sistematis dengan didukung ilustrasi, contoh penerapan dalam kehidupan sehari-hari, kegiatan praktikum, dan latihan soal yang membantu peserta didik memahami konsep secara lebih mudah dan mendalam. Melalui pendekatan ilmiah dan kontekstual, buku ini mendorong peserta didik untuk mengembangkan kemampuan berpikir kritis, analitis, dan logis dalam mengamati serta menjelaskan berbagai gejala yang berkaitan dengan zat dan perubahannya. Selain memperkuat penguasaan konsep, buku ini juga menumbuhkan sikap ilmiah, rasa ingin tahu, dan kesadaran akan pentingnya ilmu kimia dalam perkembangan ilmu pengetahuan, teknologi, dan kehidupan manusia.\r\n', NULL, NULL),
(33, 7, 'Kimia', 29, 'Drs.Unggul Sudarmo, M.Pd', 11, 25, '2023', NULL, 'Buku Kimia untuk Kelas XII yang disusun oleh Drs. Unggul Sudarmo, M.Pd. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik terhadap konsep-konsep kimia yang lebih kompleks serta penerapannya dalam kehidupan sehari-hari dan perkembangan teknologi. Materi yang disajikan mencakup berbagai topik penting, seperti sifat koligatif larutan, reaksi redoks dan elektrokimia, kimia unsur, senyawa karbon, benzena dan turunannya, polimer, serta berbagai aplikasi kimia dalam bidang industri, kesehatan, dan lingkungan. Setiap pembahasan dilengkapi dengan ilustrasi, contoh soal, kegiatan praktikum, dan latihan yang membantu peserta didik memahami konsep secara sistematis dan aplikatif. Buku ini juga mendorong peserta didik untuk mengembangkan kemampuan berpikir kritis, analitis, dan ilmiah dalam memecahkan berbagai permasalahan yang berkaitan dengan zat, reaksi kimia, dan pemanfaatannya. Dengan pendekatan yang kontekstual dan berorientasi pada pengembangan kompetensi, buku ini tidak hanya menjadi sarana penguasaan materi kimia, tetapi juga membantu peserta didik memahami peran penting ilmu kimia dalam kehidupan modern serta mempersiapkan mereka untuk melanjutkan pendidikan ke jenjang yang lebih tinggi.\r\n', NULL, NULL),
(34, 7, 'Kimia', 29, 'Bima Prasetya,S.Si, M.Pd', 11, 30, '2023', NULL, 'Buku Kimia untuk Kelas XII yang ditulis oleh Bima Prasetya, S.Si., M.Pd. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk membantu peserta didik memahami konsep-konsep kimia lanjutan serta penerapannya dalam berbagai aspek kehidupan. Buku ini menyajikan materi yang mencakup sifat koligatif larutan, reaksi redoks dan elektrokimia, kimia unsur, senyawa karbon, benzena dan turunannya, polimer, serta berbagai aplikasi ilmu kimia dalam bidang industri, kesehatan, dan lingkungan. Penyampaian materi dilakukan secara sistematis dengan dukungan ilustrasi, contoh soal, eksperimen, dan latihan yang mendorong peserta didik untuk memahami konsep secara mendalam dan mengembangkan keterampilan pemecahan masalah. Selain menekankan penguasaan teori, buku ini juga mengaitkan pembelajaran kimia dengan fenomena yang terjadi di kehidupan sehari-hari sehingga peserta didik dapat melihat manfaat nyata ilmu kimia dalam perkembangan teknologi dan masyarakat. Dengan pendekatan yang ilmiah, kontekstual, dan berorientasi pada kompetensi, buku ini tidak hanya menjadi sarana untuk meningkatkan pemahaman akademik, tetapi juga membantu menumbuhkan sikap kritis, kreatif, dan rasa ingin tahu terhadap dunia sains.', NULL, '2026-06-24 01:59:58'),
(35, 2, 'Matematika', 9, 'Drs.B.K.Noormandiri, M.Pd', 11, 50, '2023', NULL, 'Buku Matematika untuk Kelas X yang disusun oleh Drs. B.K. Noormandiri, M.Pd. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk membangun pemahaman peserta didik terhadap konsep-konsep dasar matematika sebagai fondasi dalam mempelajari materi pada jenjang yang lebih tinggi. Buku ini menyajikan berbagai topik penting, seperti bentuk aljabar, persamaan dan pertidaksamaan, fungsi, sistem persamaan linear, trigonometri, statistika, serta peluang yang dikemas secara sistematis dan mudah dipahami. Setiap materi dilengkapi dengan contoh soal, pembahasan langkah demi langkah, latihan, dan kegiatan pemecahan masalah yang membantu peserta didik mengembangkan kemampuan berpikir logis, kritis, dan analitis. Selain menekankan penguasaan konsep dan keterampilan berhitung, buku ini juga mengajak peserta didik untuk memahami penerapan matematika dalam berbagai situasi kehidupan sehari-hari. Dengan pendekatan yang terstruktur dan berorientasi pada pengembangan kompetensi, buku ini menjadi sarana pembelajaran yang efektif untuk meningkatkan kemampuan numerasi, ketelitian, serta kepercayaan diri peserta didik dalam menyelesaikan berbagai permasalahan matematika.\r\n', NULL, NULL),
(36, 3, 'Matematika', 40, 'Sudianto Manullang, Andri Kristianto SS, Tri Andri Hutapea dkk', 3, 50, '2023', NULL, 'Buku Matematika untuk Kelas XI yang disusun oleh Sudianto Manullang, Andri Kristianto, S.S., Tri Andri Hutapea, dan tim penulis lainnya serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berpikir matematis, logis, dan sistematis peserta didik. Buku ini menyajikan berbagai materi penting seperti fungsi, limit, turunan, matriks, transformasi geometri, barisan dan deret, serta konsep-konsep matematika lainnya yang menjadi dasar dalam pemecahan masalah di berbagai bidang ilmu. Setiap materi disusun secara bertahap dengan pendekatan yang mendorong peserta didik untuk mengeksplorasi konsep, menemukan pola, serta menerapkan pengetahuan matematika dalam situasi nyata. Beragam contoh, latihan, aktivitas diskusi, dan soal pemecahan masalah disajikan untuk membantu peserta didik meningkatkan kemampuan analisis, penalaran, dan komunikasi matematis. Dengan pendekatan yang berpusat pada peserta didik dan menekankan pemahaman konsep, buku ini tidak hanya mendukung pencapaian kompetensi akademik, tetapi juga membekali peserta didik dengan keterampilan berpikir kritis dan kreatif yang diperlukan dalam kehidupan sehari-hari maupun pendidikan lanjutan.\r\n', NULL, NULL),
(37, 2, 'Matematika', 9, 'Drs.Noormandiri,M.Pd', 11, 40, '2023', NULL, 'Buku Matematika untuk Kelas X yang ditulis oleh Drs. Noormandiri, M.Pd. dan diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk membantu peserta didik memahami konsep-konsep dasar matematika secara sistematis dan aplikatif. Materi yang disajikan mencakup berbagai topik penting seperti bentuk aljabar, persamaan dan pertidaksamaan, fungsi, sistem persamaan linear, trigonometri, statistika, serta peluang yang menjadi fondasi dalam pembelajaran matematika pada jenjang berikutnya. Setiap pembahasan dilengkapi dengan contoh soal, latihan bertingkat, dan kegiatan pemecahan masalah yang bertujuan mengembangkan kemampuan berpikir logis, analitis, dan kreatif. Penyajian materi yang jelas dan terstruktur membantu peserta didik memahami hubungan antar konsep serta menerapkannya dalam berbagai situasi kehidupan sehari-hari. Melalui pendekatan yang menekankan pemahaman konsep dan keterampilan numerasi, buku ini tidak hanya mendukung pencapaian kompetensi akademik, tetapi juga membangun ketelitian, kemampuan bernalar, dan kepercayaan diri peserta didik dalam menyelesaikan berbagai permasalahan matematika.\r\n', NULL, NULL);
INSERT INTO `buku` (`id`, `kelas_id`, `judul`, `rak_buku_id`, `pengarang`, `penerbit_id`, `jumlah`, `tahun`, `cover`, `deskripsi`, `created_at`, `updated_at`) VALUES
(38, 3, 'Matematika', 40, 'Prof.Sukino,M.Sc', 11, 30, '2023', NULL, 'Buku Matematika untuk Kelas XI yang disusun oleh Prof. Sukino, M.Sc. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik terhadap konsep-konsep matematika serta penerapannya dalam berbagai permasalahan nyata. Buku ini memuat beragam materi penting, seperti fungsi, limit, turunan, integral, matriks, transformasi geometri, barisan dan deret, serta statistika yang disajikan secara sistematis dan mudah dipahami. Setiap pembahasan dilengkapi dengan contoh soal, latihan, dan kegiatan pemecahan masalah yang mendorong peserta didik untuk mengembangkan kemampuan berpikir logis, kritis, dan analitis. Selain membantu penguasaan konsep dan keterampilan berhitung, buku ini juga menekankan pentingnya penalaran matematis dalam mengambil keputusan dan menyelesaikan persoalan sehari-hari. Dengan pendekatan yang terstruktur dan berorientasi pada pengembangan kompetensi, buku ini menjadi sarana pembelajaran yang efektif untuk meningkatkan kemampuan numerasi, ketelitian, serta kesiapan peserta didik dalam menghadapi jenjang pendidikan yang lebih tinggi.\r\n', NULL, NULL),
(39, 3, 'Matematika', 40, 'Pardomuan Sinambella, Mangaratua Marianus,S.Pd, Lasker Pangarapan Sinaga, Adri Kroistiano, S.Pd', 3, 40, '2023', NULL, 'Buku Matematika untuk Kelas XI yang disusun oleh Pardomuan N.J.M. Sinambela, Mangaratua Marianus, S.Pd., Lasker Pangarapan Sinaga, dan Adri Kristiano, S.Pd. serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk mengembangkan kemampuan berpikir matematis peserta didik melalui pembelajaran yang aktif, kontekstual, dan berbasis pemecahan masalah. Buku ini menyajikan berbagai materi penting, seperti induksi matematika, program linear, matriks, transformasi geometri, barisan dan deret, serta konsep-konsep matematika lainnya yang relevan dengan kehidupan sehari-hari maupun bidang ilmu lainnya. Penyajian materi dilakukan secara sistematis melalui kegiatan eksplorasi, diskusi, dan latihan yang mendorong peserta didik untuk menemukan konsep secara mandiri serta mengembangkan kemampuan bernalar, berargumentasi, dan mengomunikasikan ide-ide matematis. Selain memperkuat penguasaan konsep dan keterampilan berhitung, buku ini juga membantu peserta didik meningkatkan kemampuan berpikir kritis, kreatif, dan logis dalam menyelesaikan berbagai permasalahan. Dengan pendekatan yang berpusat pada peserta didik, buku ini tidak hanya menjadi sarana pembelajaran matematika, tetapi juga membentuk sikap teliti, disiplin, dan percaya diri dalam menghadapi tantangan akademik maupun kehidupan sehari-hari.\r\n', NULL, NULL),
(40, 7, 'Matematika', 41, 'Nolan Jennifer, Anto H, Evans Michael', 3, 50, '2023', NULL, 'Buku Matematika untuk Kelas XII yang disusun oleh Jennifer Nolan, Anto H., dan Michael Evans serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk membantu peserta didik menguasai konsep-konsep matematika tingkat lanjut serta mengembangkan kemampuan berpikir logis, kritis, dan sistematis. Buku ini menyajikan berbagai materi yang berkaitan dengan analisis matematis, statistika, peluang, kalkulus, dan pemecahan masalah yang relevan dengan kehidupan sehari-hari maupun kebutuhan akademik di jenjang pendidikan yang lebih tinggi. Setiap topik disajikan melalui penjelasan yang terstruktur, contoh-contoh aplikatif, serta latihan yang mendorong peserta didik untuk mengeksplorasi konsep dan menemukan solusi secara mandiri. Selain memperkuat kemampuan numerasi, buku ini juga mengembangkan keterampilan penalaran, komunikasi matematis, dan pengambilan keputusan berdasarkan data dan fakta. Dengan pendekatan pembelajaran yang interaktif dan berorientasi pada pemahaman konsep, buku ini menjadi sarana yang efektif untuk mempersiapkan peserta didik menghadapi tantangan akademik maupun perkembangan ilmu pengetahuan dan teknologi yang terus berkembang.\r\n', NULL, NULL),
(41, 2, 'Penjas', 5, 'Drs. Muhajir, M.Ed.', 11, 50, '2023', NULL, 'Buku Pendidikan Jasmani, Olahraga, dan Kesehatan (PJOK) untuk Kelas X yang ditulis oleh Drs. Muhajir, M.Ed. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk membantu peserta didik mengembangkan kebugaran jasmani, keterampilan gerak, serta pola hidup sehat. Buku ini memuat berbagai materi mengenai aktivitas olahraga, permainan bola besar dan bola kecil, atletik, senam, bela diri, kebugaran jasmani, serta pendidikan kesehatan yang disajikan secara sistematis dan mudah dipahami. Melalui berbagai aktivitas praktik dan pembelajaran, peserta didik diajak untuk meningkatkan kemampuan fisik, koordinasi gerak, sportivitas, disiplin, kerja sama, dan tanggung jawab. Selain menekankan pentingnya aktivitas fisik untuk menjaga kesehatan tubuh, buku ini juga memberikan pemahaman tentang pola hidup sehat, pencegahan penyakit, serta pentingnya menjaga kesehatan mental dan sosial. Dengan pendekatan yang aktif dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran olahraga, tetapi juga sebagai media untuk membentuk karakter, meningkatkan kualitas hidup, dan menumbuhkan kesadaran akan pentingnya kesehatan sepanjang hayat.\r\n', NULL, NULL),
(42, 3, 'Penjas', 32, 'Ahmad Y.Satrio', 3, 50, '2023', NULL, 'Buku Pendidikan Jasmani, Olahraga, dan Kesehatan (PJOK) untuk Kelas XI yang disusun oleh Ahmad Y. Satrio dan diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk meningkatkan kemampuan peserta didik dalam bidang kebugaran jasmani, keterampilan olahraga, serta penerapan pola hidup sehat. Buku ini menyajikan berbagai materi yang mencakup permainan dan olahraga, aktivitas kebugaran, senam, bela diri, aktivitas ritmik, serta pendidikan kesehatan yang relevan dengan kebutuhan remaja. Melalui kegiatan pembelajaran yang menekankan praktik, kerja sama, dan sportivitas, peserta didik diajak untuk mengembangkan kemampuan fisik, menjaga kesehatan tubuh, serta membangun karakter yang disiplin, tangguh, dan bertanggung jawab. Selain itu, buku ini juga membahas pentingnya gaya hidup sehat, pencegahan berbagai risiko kesehatan, serta pemanfaatan aktivitas fisik untuk meningkatkan kualitas hidup. Dengan pendekatan yang aktif, edukatif, dan kontekstual, buku ini tidak hanya mendukung pengembangan keterampilan olahraga, tetapi juga membantu peserta didik membentuk kebiasaan hidup sehat yang bermanfaat bagi kehidupan sehari-hari.\r\n', NULL, NULL),
(43, 3, 'Penjaskes', 32, 'Adang Suherman, Yudha M, Saputra Yudha Heryawan , Agus Mukholid', 5, 64, '2023', NULL, 'Buku Pendidikan Jasmani, Olahraga, dan Kesehatan (PJOK) untuk Kelas XI yang disusun oleh Adang Suherman, Yudha M. Saputra, Yudha Heryawan, dan Agus Mukholid serta diterbitkan oleh Grafindo Media Pratama merupakan sumber pembelajaran yang bertujuan mengembangkan kemampuan fisik, keterampilan olahraga, serta kesadaran hidup sehat peserta didik. Buku ini menyajikan berbagai materi yang mencakup permainan dan olahraga, aktivitas kebugaran jasmani, senam, atletik, bela diri, serta pendidikan kesehatan yang berkaitan dengan pola hidup sehat dan pencegahan berbagai gangguan kesehatan. Materi disusun secara sistematis dan didukung oleh kegiatan praktik yang mendorong peserta didik untuk aktif bergerak, bekerja sama, menjunjung tinggi sportivitas, dan meningkatkan kebugaran tubuh. Selain mengembangkan aspek fisik, buku ini juga menanamkan nilai-nilai disiplin, tanggung jawab, kerja sama, dan percaya diri melalui berbagai aktivitas pembelajaran. Dengan pendekatan yang aplikatif dan berorientasi pada pengalaman langsung, buku ini tidak hanya membantu peserta didik mencapai kompetensi dalam bidang olahraga dan kesehatan, tetapi juga membentuk gaya hidup aktif dan sehat yang bermanfaat bagi kehidupan sehari-hari.\r\n', NULL, NULL),
(44, 2, 'PPKN', 16, 'Nuryadi d, dan Tolib', 3, 30, '2024', NULL, 'Buku Pendidikan Pancasila dan Kewarganegaraan (PPKn) untuk Kelas X yang disusun oleh Nuryadi dan Tolib serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk membentuk peserta didik menjadi warga negara yang cerdas, berkarakter, dan bertanggung jawab sesuai dengan nilai-nilai Pancasila dan Undang-Undang Dasar Negara Republik Indonesia Tahun 1945. Buku ini membahas berbagai materi penting mengenai hak dan kewajiban warga negara, sistem ketatanegaraan Indonesia, demokrasi, penegakan hukum, hak asasi manusia, serta nilai-nilai kebangsaan yang menjadi dasar kehidupan bermasyarakat, berbangsa, dan bernegara. Penyajian materi dilakukan secara kontekstual melalui berbagai contoh kasus, aktivitas diskusi, dan tugas reflektif yang mendorong peserta didik untuk berpikir kritis serta memahami peran mereka sebagai bagian dari masyarakat dan bangsa Indonesia. Selain memperkuat pengetahuan kewarganegaraan, buku ini juga menanamkan sikap toleransi, gotong royong, cinta tanah air, dan semangat persatuan dalam menghadapi berbagai tantangan kehidupan berbangsa. Dengan pendekatan yang interaktif dan berbasis karakter, buku ini tidak hanya menjadi sarana pembelajaran akademik, tetapi juga mendukung pembentukan generasi yang demokratis, berintegritas, dan memiliki kepedulian terhadap lingkungan sosial di sekitarnya.\r\n', NULL, NULL),
(45, 7, 'SBK', 57, 'Achmad, Katherina Carrol, Noell Iskandar, Popoaffandi', 3, 50, '2024', NULL, 'Buku Seni Budaya dan Keterampilan (SBK) untuk Kelas XII yang disusun oleh Achmad, Katherina Carrol, Noell Iskandar, dan Popo Iskandar Afandi serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kreativitas, apresiasi, dan ekspresi seni peserta didik. Buku ini menyajikan berbagai materi yang mencakup seni rupa, seni musik, seni tari, dan seni teater dengan menekankan pemahaman konsep, apresiasi karya seni, serta kemampuan berkarya sesuai dengan potensi dan minat peserta didik. Melalui berbagai kegiatan praktik, observasi, diskusi, dan proyek kreatif, peserta didik diajak untuk mengenali nilai estetika, memahami keragaman budaya Indonesia, serta mengembangkan kemampuan berekspresi secara kreatif dan inovatif. Selain meningkatkan keterampilan artistik, buku ini juga menanamkan sikap menghargai karya seni, melestarikan budaya bangsa, serta membangun kepercayaan diri dalam menampilkan hasil karya di lingkungan sekolah maupun masyarakat. Dengan pendekatan yang interaktif dan berbasis pengalaman, buku ini tidak hanya menjadi sarana pembelajaran seni budaya, tetapi juga membantu membentuk karakter peserta didik yang kreatif, apresiatif, dan memiliki kepedulian terhadap kekayaan budaya nasional.\r\n', NULL, NULL),
(46, 3, 'Sejarah', 61, 'Ratna Hapsari, M.Adil, Prof.Dr.M.Habib Mustopo', 3, 50, '2024', NULL, 'Buku Sejarah untuk Kelas XI yang disusun oleh Ratna Hapsari, M. Adil, dan Prof. Dr. M. Habib Mustopo serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik mengenai berbagai peristiwa sejarah yang berpengaruh terhadap perkembangan bangsa Indonesia dan dunia. Buku ini membahas berbagai materi penting, seperti perkembangan kerajaan-kerajaan Nusantara, masuk dan berkembangnya agama-agama di Indonesia, masa kolonialisme dan imperialisme, pergerakan nasional, serta berbagai perubahan sosial, politik, ekonomi, dan budaya yang terjadi sepanjang perjalanan sejarah bangsa. Materi disajikan secara sistematis dan kronologis dengan dukungan sumber sejarah, peta, ilustrasi, dan aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis dalam menganalisis peristiwa masa lalu. Melalui pembelajaran sejarah, peserta didik diajak memahami hubungan sebab-akibat suatu peristiwa, menghargai perjuangan para tokoh bangsa, serta mengambil nilai-nilai positif yang dapat diterapkan dalam kehidupan masa kini. Dengan pendekatan yang kontekstual dan berbasis analisis, buku ini tidak hanya memperluas wawasan sejarah peserta didik, tetapi juga menumbuhkan sikap nasionalisme, patriotisme, dan kesadaran akan pentingnya menjaga persatuan serta identitas bangsa Indonesia.\r\n', NULL, NULL),
(47, 7, 'Sejarah', 62, 'Drs.Hermawan, dan Drs.Agus Suprijono, M.si', 3, 50, '2024', NULL, 'Buku Sejarah untuk Kelas XII yang disusun oleh Drs. Hermawan dan Drs. Agus Suprijono, M.Si. serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam mengenai berbagai peristiwa penting dalam perjalanan sejarah Indonesia dan dunia pada era modern. Materi yang disajikan mencakup perkembangan Indonesia pada masa kemerdekaan, dinamika politik dan pemerintahan, perkembangan demokrasi, perubahan sosial dan ekonomi, hubungan internasional, serta berbagai peristiwa global yang memengaruhi kehidupan bangsa Indonesia. Setiap pembahasan disusun secara sistematis dan didukung oleh sumber sejarah, ilustrasi, peta, serta kegiatan analisis yang membantu peserta didik memahami keterkaitan antara peristiwa masa lalu dan kondisi masa kini. Melalui berbagai aktivitas pembelajaran, peserta didik diajak untuk mengembangkan kemampuan berpikir kritis, menganalisis fakta sejarah, serta mengambil nilai-nilai positif dari perjuangan dan pengalaman bangsa. Dengan pendekatan yang kontekstual dan berorientasi pada pembentukan karakter, buku ini tidak hanya memperluas wawasan sejarah peserta didik, tetapi juga menumbuhkan rasa nasionalisme, tanggung jawab, dan kesadaran sebagai warga negara dalam menghadapi tantangan masa depan.\r\n', NULL, NULL),
(48, 3, 'Sejarah', 61, 'Ratna Hapsari, M.Adil, Prof.Dr.M.Habib Mustopo', 11, 24, '2024', NULL, 'Buku Sejarah untuk Kelas XI yang disusun oleh Ratna Hapsari, M. Adil, dan Prof. Dr. M. Habib Mustopo serta diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik mengenai perjalanan sejarah bangsa Indonesia dan perkembangan peradaban dunia. Buku ini mengulas berbagai peristiwa penting, mulai dari perkembangan kerajaan-kerajaan Nusantara, masuk dan berkembangnya agama-agama di Indonesia, masa kolonialisme dan imperialisme, hingga lahirnya kesadaran nasional dan perjuangan menuju kemerdekaan. Materi disajikan secara kronologis dan dilengkapi dengan peta, ilustrasi, sumber sejarah, serta berbagai aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis dan analitis dalam memahami hubungan sebab-akibat suatu peristiwa sejarah. Selain memberikan wawasan mengenai masa lalu, buku ini juga mengajak peserta didik untuk mengambil nilai-nilai keteladanan, semangat perjuangan, dan nasionalisme yang dapat diterapkan dalam kehidupan sehari-hari. Dengan pendekatan yang kontekstual dan mudah dipahami, buku ini tidak hanya menjadi sarana pembelajaran sejarah, tetapi juga membantu membentuk karakter peserta didik yang menghargai warisan bangsa dan memiliki kesadaran terhadap pentingnya persatuan serta identitas nasional.\r\n', NULL, NULL),
(49, 3, 'Sejarah (program IPA)', 59, 'Abdullah Tufiq, Sujomiharjo Bellwod Peter dan Nicolaus Suparno', 3, 25, '2024', NULL, 'Buku Sejarah Program IPA untuk Kelas XI yang disusun oleh Abdullah Taufiq, Sujomihardjo, Peter Bellwood, dan Nicolaus Suparno serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam mengenai perkembangan peradaban manusia, sejarah bangsa Indonesia, serta berbagai peristiwa penting yang memengaruhi kehidupan masyarakat hingga masa kini. Buku ini membahas beragam materi, mulai dari kehidupan manusia purba, perkembangan kebudayaan dan peradaban di Nusantara, munculnya kerajaan-kerajaan Hindu-Buddha dan Islam, hingga pengaruh kolonialisme dan imperialisme terhadap kehidupan bangsa Indonesia. Materi disajikan secara sistematis dengan dukungan peta, ilustrasi, sumber sejarah, dan berbagai kegiatan pembelajaran yang mendorong peserta didik untuk mengembangkan kemampuan berpikir kritis, analitis, dan interpretatif terhadap berbagai peristiwa sejarah. Melalui pembelajaran sejarah, peserta didik diajak memahami proses perubahan dan kesinambungan dalam kehidupan manusia serta mengambil nilai-nilai positif dari pengalaman masa lalu untuk menghadapi tantangan masa depan. Dengan pendekatan yang kontekstual dan berbasis kajian ilmiah, buku ini tidak hanya memperluas wawasan historis peserta didik, tetapi juga menumbuhkan rasa nasionalisme, penghargaan terhadap keberagaman budaya, dan kesadaran akan pentingnya menjaga identitas bangsa.\r\n', NULL, NULL),
(50, 3, 'Sejarah (program IPS)', 58, 'Christopher Pass dan Biyam Tower', 3, 25, '2024', NULL, 'Buku Sejarah Program IPS untuk Kelas XI yang disusun oleh Christopher Pass dan Bryan Towers serta diterbitkan oleh Kementerian Pendidikan merupakan bahan ajar yang dirancang untuk memperluas wawasan peserta didik mengenai perkembangan sejarah, sosial, ekonomi, dan peradaban manusia dari masa ke masa. Buku ini membahas berbagai peristiwa penting yang memengaruhi perjalanan bangsa Indonesia dan dunia, termasuk perkembangan masyarakat, sistem ekonomi, kolonialisme dan imperialisme, kebangkitan nasional, serta perubahan sosial dan politik yang membentuk kehidupan modern. Materi disajikan secara sistematis dengan memadukan fakta sejarah, data, ilustrasi, dan berbagai aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis dalam menganalisis hubungan antara peristiwa masa lalu dan kondisi masa kini. Selain memberikan pemahaman tentang proses perubahan dan perkembangan masyarakat, buku ini juga menanamkan nilai-nilai nasionalisme, tanggung jawab, dan penghargaan terhadap keberagaman budaya. Dengan pendekatan yang kontekstual dan berbasis analisis, buku ini tidak hanya menjadi sarana pembelajaran sejarah, tetapi juga membantu peserta didik mengembangkan kemampuan berpikir logis dan memahami dinamika kehidupan sosial yang terus berkembang.\r\n', NULL, NULL),
(51, 2, 'Sejarah Peminatan', 14, 'Ratna Hapsari, M.Adil, Prof.Dr.M.Habib Mustopo', 11, 24, '2024', NULL, 'Buku Sejarah Peminatan untuk Kelas X yang disusun oleh Ratna Hapsari, M. Adil, dan Prof. Dr. M. Habib Mustopo serta diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman yang lebih mendalam mengenai konsep dasar ilmu sejarah, perkembangan peradaban manusia, serta metode kajian sejarah sebagai ilmu pengetahuan. Buku ini membahas berbagai materi penting, seperti pengertian dan ruang lingkup sejarah, konsep waktu dalam sejarah, penelitian sejarah, manusia purba, asal-usul nenek moyang bangsa Indonesia, serta perkembangan kebudayaan masyarakat Nusantara pada masa awal. Materi disajikan secara sistematis dengan dukungan sumber sejarah, ilustrasi, peta, dan berbagai aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis, analitis, dan objektif dalam memahami peristiwa masa lalu. Melalui pendekatan yang berbasis penelusuran fakta dan interpretasi sejarah, peserta didik diajak untuk memahami proses perubahan dan kesinambungan yang terjadi dalam kehidupan manusia dari masa ke masa. Dengan penyajian yang kontekstual dan mendalam, buku ini tidak hanya memperluas wawasan sejarah peserta didik, tetapi juga menumbuhkan kesadaran sejarah, rasa nasionalisme, serta penghargaan terhadap warisan budaya dan perjalanan bangsa Indonesia.\r\n', NULL, NULL),
(52, 3, 'Sejarah Peminatan', 48, 'Drs.Hermawan, dan Drs.Agus Suprijono, M.si', 11, 24, '2024', NULL, 'Buku Sejarah Peminatan untuk Kelas XI yang disusun oleh Drs. Hermawan dan Drs. Agus Suprijono, M.Si. serta diterbitkan oleh PT Erlangga merupakan bahan ajar yang dirancang untuk memperdalam pemahaman peserta didik mengenai berbagai peristiwa sejarah yang membentuk perkembangan bangsa Indonesia dan dunia. Buku ini membahas secara lebih rinci perjalanan sejarah mulai dari perkembangan kerajaan-kerajaan besar di Nusantara, pengaruh masuknya berbagai kebudayaan dan agama, masa kolonialisme dan imperialisme, hingga munculnya pergerakan nasional yang menjadi fondasi perjuangan kemerdekaan Indonesia. Materi disajikan secara kronologis dan didukung oleh sumber-sumber sejarah, peta, ilustrasi, serta kegiatan analisis yang mendorong peserta didik untuk mengembangkan kemampuan berpikir kritis, interpretatif, dan objektif dalam memahami peristiwa masa lalu. Melalui pembelajaran yang berbasis kajian sejarah, peserta didik diajak untuk menelaah hubungan sebab-akibat, perubahan, dan kesinambungan dalam perjalanan sejarah manusia. Dengan pendekatan yang kontekstual dan mendalam, buku ini tidak hanya memperkaya wawasan historis peserta didik, tetapi juga menumbuhkan sikap nasionalisme, penghargaan terhadap keberagaman budaya, serta kesadaran akan pentingnya mempelajari sejarah sebagai pedoman dalam menghadapi masa depan.\r\n', NULL, NULL),
(54, 3, 'Senibudaya', 56, 'Achmad, Katherina Carrol, Noell Iskandar, Popoaffandi', 3, 50, '2024', NULL, 'Buku Seni Budaya untuk Kelas XI yang disusun oleh Achmad, Katherina Carrol, Noell Iskandar, dan Popo Iskandar Afandi serta diterbitkan oleh Kementerian Pendidikan merupakan sumber pembelajaran yang bertujuan mengembangkan kreativitas, apresiasi, dan kemampuan berekspresi peserta didik melalui berbagai bidang seni. Buku ini menyajikan materi yang mencakup seni rupa, seni musik, seni tari, dan seni teater dengan penekanan pada pemahaman konsep, pengenalan unsur-unsur seni, apresiasi terhadap karya seni, serta pengembangan keterampilan berkarya secara kreatif dan inovatif. Melalui berbagai kegiatan observasi, praktik, diskusi, dan proyek seni, peserta didik diajak untuk memahami nilai estetika, mengenali keberagaman budaya Indonesia, serta mengekspresikan ide dan gagasan melalui karya seni. Selain meningkatkan kemampuan artistik, buku ini juga menanamkan sikap apresiatif, percaya diri, kerja sama, dan tanggung jawab dalam proses berkesenian. Dengan pendekatan yang interaktif dan berbasis pengalaman, buku ini tidak hanya menjadi sarana pembelajaran seni budaya, tetapi juga membantu peserta didik mengembangkan kepekaan sosial, kreativitas, dan kecintaan terhadap warisan budaya bangsa.\r\n', NULL, NULL),
(55, 3, 'SKI', 23, 'Abdullah, Taufiq Ahmad Wahid.A.Jamil dan Nasution Harun dkk', 1, 118, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas XI yang disusun oleh Abdullah, Taufiq Ahmad, A. Jamil, Harun Nasution, dan tim penulis lainnya serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam mengenai perkembangan peradaban dan kebudayaan Islam pada berbagai periode sejarah. Buku ini membahas perjalanan dakwah Islam, perkembangan ilmu pengetahuan, kebudayaan, pemerintahan, serta kontribusi para tokoh muslim dalam membangun peradaban yang berpengaruh bagi dunia. Materi disajikan secara sistematis dan kronologis sehingga peserta didik dapat memahami proses perkembangan masyarakat Islam dari masa ke masa serta pengaruhnya terhadap kehidupan sosial, politik, ekonomi, dan budaya. Melalui berbagai kisah keteladanan tokoh-tokoh Islam, peserta didik diajak untuk meneladani nilai-nilai keilmuan, kepemimpinan, kerja keras, toleransi, dan semangat dalam menuntut ilmu. Dengan dukungan ilustrasi, sumber sejarah, dan aktivitas pembelajaran yang interaktif, buku ini tidak hanya memperluas wawasan sejarah peserta didik, tetapi juga menumbuhkan kecintaan terhadap peradaban Islam serta membentuk karakter yang berakhlak mulia dan berwawasan luas.\r\n', NULL, NULL),
(56, 7, 'SKI', 23, 'Abdul Hakim Al-Afif, Sumanto Al-Qurtuby, Hasan Muafir Ambary', 1, 84, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas XII Madrasah Aliyah yang disusun oleh Abdul Hakim Al-Afif, Sumanto Al-Qurtuby, dan Hasan Mufair Ambary serta diterbitkan oleh PT Tiga Serangkai Pustaka Mandiri merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mengenai perkembangan peradaban Islam pada masa modern hingga kontemporer. Buku ini membahas berbagai materi seperti dinamika perkembangan umat Islam di berbagai wilayah dunia, kebangkitan intelektual Islam, perkembangan lembaga pendidikan Islam, peran tokoh-tokoh pembaharu, serta kontribusi umat Islam dalam bidang sosial, politik, ekonomi, dan ilmu pengetahuan.x\r\nMateri disajikan secara sistematis dan kronologis sehingga peserta didik dapat memahami kesinambungan sejarah Islam dari masa klasik hingga modern. Selain itu, buku ini juga menekankan nilai-nilai keteladanan seperti semangat keilmuan, kepemimpinan, toleransi, dan tanggung jawab dalam menjaga serta mengembangkan ajaran Islam di tengah perubahan zaman. Dengan pendekatan yang kontekstual dan disertai aktivitas pembelajaran yang interaktif, buku ini tidak hanya memperkaya wawasan sejarah peserta didik, tetapi juga membentuk karakter yang berakhlak mulia, berwawasan luas, serta memiliki kepedulian terhadap perkembangan umat Islam di tingkat global.\r\n', NULL, NULL),
(57, 2, 'Sosiologi', 7, 'Susanto Phil Astrid.S', 5, 50, '2024', NULL, 'Buku Sosiologi untuk Kelas X yang disusun oleh Susanto dan Phil Astrid S. serta diterbitkan oleh Grafindo Media Pratama merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai konsep-konsep sosiologi serta fenomena sosial dalam kehidupan masyarakat. Buku ini membahas berbagai materi penting seperti pengertian sosiologi, objek kajian sosiologi, interaksi sosial, nilai dan norma sosial, sosialisasi, kelompok sosial, serta dinamika kehidupan masyarakat. Penyajian materi dilakukan secara sistematis dengan mengaitkan teori sosiologi dengan peristiwa dan fenomena yang terjadi di lingkungan sekitar peserta didik sehingga lebih mudah dipahami dan relevan dengan kehidupan sehari-hari.\r\n\r\nMelalui berbagai contoh kasus, ilustrasi, serta kegiatan analisis sosial, peserta didik diajak untuk mengembangkan kemampuan berpikir kritis dalam memahami hubungan sosial dan perubahan yang terjadi dalam masyarakat. Buku ini juga mendorong peserta didik untuk peka terhadap permasalahan sosial serta mampu memberikan pandangan yang objektif dalam menyikapi berbagai fenomena sosial. Dengan pendekatan yang kontekstual dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sosiologi, tetapi juga membantu membentuk kesadaran sosial, sikap peduli, dan kemampuan beradaptasi dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(58, 2, 'Akidah Akhlak', 23, 'Nurul Hidayah', 6, 150, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas X Madrasah Aliyah yang disusun oleh Nurul Hidayah dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperkuat pemahaman peserta didik mengenai dasar-dasar keimanan serta pembentukan akhlak mulia dalam kehidupan sehari-hari. Buku ini membahas berbagai materi penting seperti konsep akidah Islam, iman kepada Allah, malaikat, kitab-kitab, rasul, hari akhir, serta qada dan qadar, yang menjadi fondasi keyakinan seorang muslim. Selain itu, buku ini juga menguraikan pembentukan akhlak terpuji seperti kejujuran, amanah, disiplin, tanggung jawab, serta upaya menghindari akhlak tercela dalam kehidupan pribadi maupun sosial.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan nilai-nilai keislaman dengan realitas kehidupan sehari-hari. Melalui berbagai aktivitas pembelajaran, diskusi, dan latihan, peserta didik diajak untuk tidak hanya memahami konsep secara teoritis, tetapi juga mengamalkannya dalam perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga sebagai media untuk membentuk pribadi muslim yang beriman, bertakwa, berakhlak mulia, serta mampu berperan positif dalam lingkungan keluarga, sekolah, dan masyarakat.\r\n', NULL, NULL),
(59, 3, 'Akidah Akhlak', 23, 'Sihabul Milahuddin', 6, 147, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas XI Madrasah Aliyah yang disusun oleh Sihabul Milahuddin dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai aspek keimanan dan pembentukan akhlak dalam ajaran Islam. Buku ini membahas berbagai materi penting seperti penguatan akidah Islam, sifat-sifat Allah, iman kepada malaikat, kitab, rasul, hari akhir, serta qada dan qadar, yang menjadi landasan keyakinan seorang muslim. Selain itu, buku ini juga menekankan pembinaan akhlak terpuji seperti jujur, amanah, disiplin, tanggung jawab, serta sikap menghormati orang tua dan guru, sekaligus menjauhi akhlak tercela dalam kehidupan sehari-hari.\r\n\r\nMateri disusun secara sistematis dan kontekstual sehingga peserta didik dapat memahami keterkaitan antara ajaran agama dengan realitas kehidupan sosial. Melalui berbagai kegiatan pembelajaran, diskusi, dan refleksi, peserta didik didorong untuk tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengimplementasikannya dalam perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga sebagai media untuk membentuk pribadi muslim yang beriman, berakhlak mulia, dan mampu memberikan kontribusi positif dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(60, 7, 'Akidah Akhlak', 23, 'A. Yusuf Alfi Syahr', 6, 165, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas XII Madrasah Aliyah yang disusun oleh A. Yusuf Alfi Syahr dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai aspek keimanan dan pembentukan akhlak dalam Islam pada tingkat lanjutan. Buku ini membahas berbagai materi penting seperti penguatan iman kepada Allah SWT beserta sifat-sifat-Nya, iman kepada malaikat, kitab-kitab Allah, rasul, hari akhir, serta qada dan qadar sebagai dasar keyakinan seorang muslim. Selain itu, buku ini juga menekankan pembinaan akhlak terpuji seperti kejujuran, tanggung jawab, disiplin, amanah, serta sikap toleransi dalam kehidupan sosial, sekaligus menghindari akhlak tercela yang dapat merusak hubungan antarindividu maupun masyarakat.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan nilai-nilai akidah dan akhlak dengan realitas kehidupan sehari-hari. Melalui berbagai kegiatan pembelajaran, diskusi, dan refleksi, peserta didik diarahkan untuk tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku nyata. Dengan pendekatan yang berorientasi pada penguatan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga sebagai media pembentukan pribadi muslim yang beriman, berakhlak mulia, serta mampu berperan aktif dan positif dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(61, 2, 'AL Quran Hadist', 23, 'Syaifullah Amin', 6, 150, '2024', NULL, 'Buku Al-Qur’an Hadis untuk Kelas X Madrasah Aliyah yang disusun oleh Syaifullah Amin dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam kepada peserta didik mengenai Al-Qur’an dan hadis sebagai pedoman utama dalam kehidupan seorang muslim. Buku ini membahas berbagai materi penting seperti kedudukan dan fungsi Al-Qur’an dan hadis dalam Islam, cara memahami kandungan ayat-ayat Al-Qur’an, hadis sebagai sumber hukum kedua setelah Al-Qur’an, serta penerapan nilai-nilai Al-Qur’an dan hadis dalam kehidupan sehari-hari.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan ajaran Al-Qur’an dan hadis dengan realitas kehidupan. Melalui berbagai kegiatan pembelajaran seperti membaca, memahami makna, diskusi, dan refleksi, peserta didik diarahkan tidak hanya memahami teks secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga sebagai media untuk membentuk pribadi muslim yang beriman, bertakwa, serta berakhlak mulia dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(62, 3, 'AL Quran Hadist', 23, 'Pahruroji M. Bukhori', 6, 147, '2024', NULL, 'Buku Al-Qur’an Hadis untuk Kelas XI Madrasah Aliyah yang disusun oleh Pahruroji dan M. Bukhori serta diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai Al-Qur’an dan hadis sebagai pedoman utama dalam kehidupan umat Islam. Buku ini memuat berbagai materi penting seperti kedudukan dan fungsi Al-Qur’an dan hadis, pemahaman kandungan ayat-ayat pilihan, hadis-hadis tentang akhlak dan kehidupan sosial, serta penerapan nilai-nilai Al-Qur’an dan hadis dalam kehidupan sehari-hari.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan ajaran agama dengan realitas kehidupan di lingkungan sekitar. Melalui berbagai aktivitas pembelajaran seperti membaca, memahami, menghafal, berdiskusi, dan refleksi, peserta didik diarahkan untuk tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, bertakwa, serta berakhlak mulia dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(63, 7, 'AL Quran Hadist', 23, 'M. Abdul Jalil', 6, 165, '2024', NULL, 'Buku Al-Qur’an Hadis untuk Kelas XII Madrasah Aliyah yang disusun oleh M. Abdul Jalil dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai Al-Qur’an dan hadis sebagai pedoman utama dalam kehidupan seorang muslim pada tingkat lanjutan. Buku ini membahas berbagai materi penting seperti kedudukan Al-Qur’an dan hadis sebagai sumber hukum Islam, pemahaman ayat-ayat dan hadis pilihan, nilai-nilai akhlak dalam Al-Qur’an dan hadis, serta penerapan ajaran Islam dalam kehidupan pribadi, sosial, dan kemasyarakatan.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan ajaran Al-Qur’an dan hadis dengan berbagai fenomena kehidupan nyata. Melalui kegiatan pembelajaran seperti membaca, memahami makna, menghafal, berdiskusi, dan refleksi, peserta didik diarahkan untuk tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku sehari-hari. Dengan pendekatan yang berorientasi pada penguatan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, bertakwa, dan berakhlak mulia dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(64, 2, 'Fikih', 23, 'Muh. Asy ari', 6, 150, '2024', NULL, 'Buku Fikih untuk Kelas X Madrasah Aliyah yang disusun oleh Muh. Asy’ari merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai hukum-hukum Islam yang berkaitan dengan kehidupan sehari-hari. Buku ini membahas berbagai materi penting seperti pengertian dan ruang lingkup fikih, sumber hukum Islam, thaharah (bersuci), salat, zakat, puasa, serta ketentuan-ketentuan ibadah lainnya yang menjadi dasar praktik keagamaan umat Islam.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat memahami hubungan antara teori fikih dengan praktik ibadah dalam kehidupan nyata. Melalui berbagai kegiatan pembelajaran seperti diskusi, latihan soal, dan praktik ibadah, peserta didik diarahkan untuk tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dengan benar sesuai tuntunan syariat. Dengan pendekatan yang berorientasi pada pembentukan karakter religius, buku ini tidak hanya menjadi sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang taat, disiplin, dan bertanggung jawab dalam menjalankan ajaran Islam.\r\n', NULL, NULL),
(65, 3, 'Fikih', 23, 'Atmo Prawiro', 6, 147, '2024', NULL, 'Buku Fikih untuk Kelas XI Madrasah Aliyah yang disusun oleh Atmo Prawiro dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai hukum-hukum Islam dalam kehidupan sehari-hari. Buku ini memuat berbagai materi lanjutan yang mencakup pembahasan tentang muamalah, jinayah, munakahat, waris, serta berbagai ketentuan fikih yang berkaitan dengan interaksi sosial dan kehidupan bermasyarakat dalam perspektif Islam.\r\n\r\nPenyajian materi disusun secara sistematis dan kontekstual sehingga peserta didik dapat memahami keterkaitan antara konsep fikih dengan penerapannya dalam kehidupan nyata. Melalui berbagai kegiatan pembelajaran seperti diskusi, studi kasus, dan latihan penerapan hukum Islam, peserta didik diarahkan untuk tidak hanya memahami teori, tetapi juga mampu mengamalkannya sesuai tuntunan syariat. Dengan pendekatan yang berorientasi pada pembentukan karakter religius, buku ini tidak hanya menjadi sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang taat, berilmu, dan bijaksana dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(66, 7, 'Fikih', 23, 'Dewi Masyithoh', 6, 165, '2024', NULL, 'Buku Fikih untuk Kelas XII Madrasah Aliyah yang disusun oleh Dewi Masyithoh dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman lanjutan mengenai hukum-hukum Islam yang berkaitan dengan kehidupan individu maupun sosial. Buku ini membahas berbagai materi penting seperti muamalah, jinayah, munakahat, waris, serta berbagai ketentuan fikih yang mengatur interaksi dalam kehidupan bermasyarakat sesuai dengan prinsip syariat Islam.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat memahami keterkaitan antara konsep fikih dengan penerapannya dalam kehidupan sehari-hari. Melalui berbagai kegiatan pembelajaran seperti diskusi, studi kasus, dan latihan penerapan hukum Islam, peserta didik diarahkan tidak hanya memahami teori, tetapi juga mampu mengamalkannya dalam praktik kehidupan nyata. Dengan pendekatan yang berorientasi pada penguatan karakter religius dan tanggung jawab, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang berilmu, taat, dan bijaksana dalam menjalani kehidupan bermasyarakat.\r\n', NULL, NULL),
(67, 2, 'Bahasa Arab', 23, 'Muh. Ilyas', 6, 147, '2024', NULL, 'Buku Bahasa Arab untuk Kelas X Madrasah Aliyah yang disusun oleh Muh. Ilyas dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan dasar kemampuan berbahasa Arab kepada peserta didik. Buku ini memuat berbagai materi penting seperti kosakata (mufradat), struktur kalimat (qawa’id), percakapan sederhana (hiwar), membaca teks (qira’ah), serta latihan menulis (kitabah) yang disusun secara bertahap sesuai tingkat kemampuan siswa.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat memahami dan menggunakan bahasa Arab dalam situasi sehari-hari maupun dalam konteks keagamaan. Melalui berbagai latihan, dialog, dan kegiatan pembelajaran, peserta didik diarahkan untuk mengembangkan keterampilan berbahasa secara aktif, baik lisan maupun tulisan. Dengan pendekatan yang komunikatif dan berorientasi pada keterampilan praktis, buku ini tidak hanya menjadi sarana pembelajaran bahasa Arab, tetapi juga membantu peserta didik dalam memahami sumber ajaran Islam yang berbahasa Arab secara lebih baik.\r\n', NULL, NULL),
(68, 3, 'Bahasa Arab', 23, 'Risna Rianti Sari, dan Hasyim Amirullah', 6, 150, '2024', NULL, 'Buku Bahasa Arab untuk Kelas XI Madrasah Aliyah yang disusun oleh Risna Rianti Sari dan Hasyim Amirullah merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa Arab peserta didik secara lebih lanjut setelah tingkat dasar. Buku ini memuat berbagai materi pembelajaran yang mencakup penguasaan kosakata (mufradat), struktur kalimat (qawa’id), percakapan (hiwar), membaca teks (qira’ah), serta keterampilan menulis (kitabah) dengan tingkat kesulitan yang lebih kompleks.\r\n\r\nMateri disajikan secara sistematis dan komunikatif sehingga peserta didik dapat mengembangkan kemampuan memahami dan menggunakan bahasa Arab dalam berbagai situasi kehidupan sehari-hari maupun dalam konteks keagamaan. Melalui latihan-latihan, dialog, dan aktivitas pembelajaran yang interaktif, peserta didik didorong untuk lebih aktif dalam mengasah keterampilan berbahasa, baik lisan maupun tulisan. Dengan pendekatan yang berorientasi pada keterampilan komunikatif dan pemahaman teks, buku ini tidak hanya menjadi sarana pembelajaran bahasa Arab, tetapi juga membantu peserta didik dalam memahami literatur keislaman yang berbahasa Arab secara lebih baik.\r\n', NULL, NULL),
(69, 7, 'Bahasa Arab', 23, 'Alfiatus Syarofah, Muhammad Yasin, dan Fatchul Barry', 6, 165, '2024', NULL, 'Buku Bahasa Arab untuk Kelas XII Madrasah Aliyah yang disusun oleh Alfiatus Syarofah, Muhammad Yasin, dan Fatchul Barry serta diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran lanjutan yang dirancang untuk mengembangkan kemampuan berbahasa Arab peserta didik secara lebih mendalam. Buku ini memuat berbagai materi yang mencakup penguatan kosakata (mufradat), struktur kalimat (qawa’id), percakapan (hiwar), membaca teks (qira’ah), serta keterampilan menulis (kitabah) dengan tingkat yang lebih kompleks dan aplikatif.\r\n\r\nPenyajian materi dilakukan secara sistematis, komunikatif, dan kontekstual sehingga peserta didik dapat memahami serta menggunakan bahasa Arab dalam berbagai situasi, baik dalam kehidupan sehari-hari maupun dalam konteks keagamaan. Melalui latihan-latihan, dialog, serta aktivitas pembelajaran yang interaktif, peserta didik diarahkan untuk mengasah kemampuan berbahasa secara aktif, baik lisan maupun tulisan. Dengan pendekatan yang berorientasi pada keterampilan komunikatif dan pemahaman teks keislaman, buku ini tidak hanya berfungsi sebagai sarana pembelajaran bahasa Arab, tetapi juga membantu peserta didik dalam memahami sumber-sumber ajaran Islam yang berbahasa Arab secara lebih mendalam.\r\n', NULL, NULL),
(70, 2, 'SKI', 23, 'Elfa Tsuroyya, S.Ag., M.Pd.I', 6, 147, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas X Madrasah Aliyah yang disusun oleh Elfa Tsuroyya, S.Ag., M.Pd.I. dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai perkembangan sejarah dan kebudayaan Islam sejak masa awal hingga perkembangan peradaban Islam di berbagai wilayah.\r\n\r\nBuku ini memuat berbagai materi penting seperti sejarah lahirnya Islam, keteladanan Rasulullah SAW dalam membangun masyarakat Madinah, perkembangan dakwah Islam pada masa Khulafaur Rasyidin, serta dinamika penyebaran Islam di berbagai kawasan dunia. Selain itu, buku ini juga menekankan nilai-nilai keislaman seperti kejujuran, tanggung jawab, toleransi, dan semangat perjuangan dalam menegakkan ajaran Islam.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat memahami keterkaitan antara peristiwa sejarah dengan pembentukan nilai-nilai kehidupan. Melalui berbagai kegiatan pembelajaran, diskusi, dan analisis, peserta didik diarahkan untuk tidak hanya memahami fakta sejarah, tetapi juga mengambil pelajaran moral dan keteladanan dari perjalanan sejarah Islam. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran SKI, tetapi juga membantu membentuk pribadi yang berakhlak mulia, berwawasan sejarah, dan memiliki kecintaan terhadap peradaban Islam.\r\n', NULL, NULL),
(71, 3, 'SKI', 23, 'Moh. Sulaiman', 6, 150, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas XI Madrasah Aliyah yang disusun oleh Moh. Sulaiman dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman lebih mendalam mengenai perkembangan peradaban Islam pada masa pertengahan hingga awal modern.\r\n\r\nBuku ini memuat berbagai materi penting seperti perkembangan Dinasti Umayyah dan Abbasiyah, kemajuan ilmu pengetahuan dalam dunia Islam, tokoh-tokoh ilmuwan Muslim, perkembangan kebudayaan Islam di berbagai wilayah, serta dinamika penyebaran Islam ke berbagai belahan dunia. Selain itu, buku ini juga menekankan nilai-nilai keteladanan seperti semangat keilmuan, kepemimpinan, kerja keras, toleransi, dan kontribusi umat Islam dalam membangun peradaban dunia.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kronologis sehingga peserta didik dapat memahami hubungan antarperistiwa sejarah secara runtut. Melalui kegiatan pembelajaran, diskusi, dan analisis, peserta didik diarahkan untuk tidak hanya memahami fakta sejarah, tetapi juga mampu mengambil nilai-nilai positif dari setiap peristiwa. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran SKI, tetapi juga membantu membentuk pribadi yang berwawasan sejarah, berakhlak mulia, dan memiliki kecintaan terhadap peradaban Islam.\r\n', NULL, NULL),
(72, 7, 'SKI', 23, 'M. Syamsul Arifin,S.Pd', 6, 165, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas XII Madrasah Aliyah yang disusun oleh M. Syamsul Arifin, S.Pd. merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman lanjutan mengenai perkembangan peradaban Islam pada masa modern hingga kontemporer. Buku ini membahas berbagai materi penting seperti dinamika umat Islam di berbagai belahan dunia, pembaruan pemikiran Islam, perkembangan lembaga pendidikan Islam, peran tokoh-tokoh pembaharu, serta kontribusi umat Islam dalam bidang sosial, politik, ekonomi, dan ilmu pengetahuan.\r\n\r\nMateri disajikan secara sistematis dan kronologis sehingga peserta didik dapat memahami kesinambungan sejarah Islam dari masa sebelumnya hingga perkembangan modern. Selain itu, buku ini juga menekankan nilai-nilai keteladanan seperti semangat keilmuan, kepemimpinan, toleransi, dan tanggung jawab dalam menghadapi tantangan zaman. Melalui pendekatan yang kontekstual dan aktivitas pembelajaran yang interaktif, buku ini tidak hanya memperluas wawasan sejarah peserta didik, tetapi juga membentuk karakter yang berakhlak mulia, berwawasan luas, serta memiliki kepedulian terhadap perkembangan umat Islam di tingkat global.\r\n', NULL, NULL),
(73, 2, 'Akidah Akhlak', 23, 'Nurul Hidayah', 6, 25, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas X Madrasah Aliyah yang disusun oleh Nurul Hidayah dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai keyakinan (akidah) dan pembentukan akhlak dalam ajaran Islam. Buku ini menjadi pedoman bagi peserta didik dalam memahami prinsip-prinsip keimanan sekaligus mengamalkannya dalam kehidupan sehari-hari.\r\n\r\nMateri yang disajikan mencakup rukun iman, yaitu iman kepada Allah, malaikat, kitab-kitab Allah, rasul, hari akhir, serta qada dan qadar. Selain itu, buku ini juga membahas pembinaan akhlak terpuji seperti jujur, amanah, disiplin, tanggung jawab, serta upaya menjauhi akhlak tercela dalam kehidupan pribadi maupun sosial. Seluruh materi disusun secara sistematis dan kontekstual sehingga mudah dipahami dan relevan dengan kehidupan peserta didik.\r\n\r\nMelalui berbagai kegiatan pembelajaran seperti diskusi, latihan, dan refleksi, peserta didik diarahkan tidak hanya memahami konsep keagamaan secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku sehari-hari. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, berakhlak mulia, serta bertanggung jawab dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(74, 2, 'AL Quran Hadist', 23, 'Syaifullah Amin', 6, 25, '2024', NULL, 'Buku Al-Qur’an Hadis untuk Kelas X Madrasah Aliyah yang disusun oleh Syaifullah Amin dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar kepada peserta didik mengenai Al-Qur’an dan hadis sebagai pedoman utama dalam kehidupan umat Islam.\r\n\r\nBuku ini memuat materi penting seperti kedudukan dan fungsi Al-Qur’an dan hadis sebagai sumber ajaran Islam, cara memahami kandungan ayat-ayat Al-Qur’an dan hadis, serta penerapan nilai-nilai yang terkandung di dalamnya dalam kehidupan sehari-hari. Selain itu, peserta didik juga diarahkan untuk memahami pentingnya menjadikan Al-Qur’an dan hadis sebagai dasar dalam bersikap, berperilaku, serta mengambil keputusan.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga mudah dipahami serta relevan dengan kehidupan peserta didik. Melalui berbagai kegiatan pembelajaran seperti membaca, menghafal, diskusi, dan refleksi, peserta didik tidak hanya diajak untuk memahami teori, tetapi juga mengamalkannya dalam kehidupan nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, bertakwa, dan berakhlak mulia.\r\n', NULL, NULL);
INSERT INTO `buku` (`id`, `kelas_id`, `judul`, `rak_buku_id`, `pengarang`, `penerbit_id`, `jumlah`, `tahun`, `cover`, `deskripsi`, `created_at`, `updated_at`) VALUES
(75, 2, 'Fikih', 23, 'M. Asy ari', 6, 25, '2024', NULL, 'Buku Fikih untuk Kelas X Madrasah Aliyah yang disusun oleh M. Asy’ari dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai hukum-hukum Islam yang berkaitan dengan ibadah dan kehidupan sehari-hari.\r\n\r\nBuku ini membahas berbagai materi penting seperti konsep dasar fikih, sumber hukum Islam, thaharah (bersuci), salat, zakat, puasa, serta ketentuan-ketentuan ibadah lainnya yang menjadi dasar dalam praktik keagamaan umat Islam. Seluruh materi disajikan secara sistematis dan mudah dipahami sehingga peserta didik dapat menghubungkan teori dengan praktik dalam kehidupan nyata.\r\n\r\nMelalui berbagai kegiatan pembelajaran seperti diskusi, latihan, dan praktik ibadah, peserta didik diarahkan tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya sesuai tuntunan syariat Islam. Dengan pendekatan yang berorientasi pada pembentukan karakter religius, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang taat, disiplin, dan bertanggung jawab dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(76, 3, 'Sosiologi', 36, 'Kun Mariati', 11, 30, '2024', NULL, 'Buku Sosiologi untuk Kelas XI yang disusun oleh Kun Maryati dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep-konsep sosiologi serta dinamika kehidupan sosial dalam masyarakat. Buku ini membahas berbagai materi penting seperti struktur sosial, diferensiasi dan stratifikasi sosial, konflik dan integrasi sosial, perubahan sosial, lembaga sosial, serta globalisasi dan dampaknya terhadap kehidupan masyarakat.\r\n\r\nMateri disajikan secara sistematis dengan mengaitkan teori sosiologi dengan fenomena sosial yang terjadi di lingkungan sekitar, sehingga peserta didik dapat memahami keterkaitan antara konsep akademik dan realitas kehidupan sehari-hari. Melalui berbagai contoh kasus, ilustrasi, dan kegiatan analisis sosial, peserta didik diarahkan untuk mengembangkan kemampuan berpikir kritis, peka terhadap masalah sosial, serta mampu memberikan solusi yang rasional terhadap berbagai permasalahan dalam masyarakat.\r\n\r\nDengan pendekatan yang kontekstual dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sosiologi, tetapi juga membantu membentuk kesadaran sosial, sikap toleransi, serta kemampuan beradaptasi dalam kehidupan bermasyarakat yang majemuk dan terus berkembang.\r\n', NULL, NULL),
(77, 2, 'Kimia', 3, 'Drs. Unggul Sudarmo', 11, 25, '2024', NULL, 'Buku Kimia untuk Kelas X yang disusun oleh Drs. Unggul Sudarmo dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai konsep-konsep kimia sebagai ilmu yang mempelajari materi, struktur, sifat, dan perubahan zat.\r\n\r\nBuku ini membahas berbagai materi penting seperti hakikat ilmu kimia, metode ilmiah, keselamatan kerja di laboratorium, struktur atom, sistem periodik unsur, ikatan kimia, tata nama senyawa, serta konsep dasar perhitungan kimia. Seluruh materi disusun secara sistematis agar peserta didik dapat memahami keterkaitan antara teori kimia dan fenomena yang terjadi dalam kehidupan sehari-hari.\r\n\r\nMelalui berbagai contoh soal, kegiatan praktikum, dan latihan, peserta didik diarahkan untuk mengembangkan kemampuan berpikir ilmiah, analitis, serta keterampilan dalam memecahkan masalah. Dengan pendekatan yang kontekstual dan berbasis kompetensi, buku ini tidak hanya berfungsi sebagai sarana pembelajaran kimia, tetapi juga membantu membentuk sikap ilmiah, rasa ingin tahu, serta kesadaran akan pentingnya ilmu kimia dalam perkembangan ilmu pengetahuan dan teknologi.\r\n', NULL, NULL),
(78, 3, 'Sejarah', 61, 'Ratna Hapsari, dan M.Adil', 11, 30, '2024', NULL, 'Buku Sejarah untuk Kelas XI yang disusun oleh Ratna Hapsari dan M. Adil serta diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai perjalanan sejarah bangsa Indonesia dan perkembangan peradaban dunia. Buku ini menyajikan berbagai materi penting seperti perkembangan kerajaan-kerajaan di Nusantara, masuk dan berkembangnya agama dan kebudayaan di Indonesia, masa kolonialisme dan imperialisme, hingga lahirnya pergerakan nasional yang menjadi tonggak perjuangan menuju kemerdekaan Indonesia.\r\n\r\nMateri disajikan secara kronologis dan sistematis dengan dukungan peta, ilustrasi, sumber sejarah, serta berbagai aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis dan analitis dalam memahami peristiwa sejarah. Melalui pendekatan kontekstual, peserta didik diajak untuk melihat hubungan sebab-akibat, perubahan, serta kesinambungan dalam sejarah sehingga mampu memahami makna dari setiap peristiwa yang terjadi.\r\n\r\nSelain memperkaya wawasan sejarah, buku ini juga menanamkan nilai-nilai nasionalisme, cinta tanah air, serta penghargaan terhadap jasa para tokoh bangsa. Dengan pendekatan pembelajaran yang aktif dan berorientasi pada penguatan karakter, buku ini tidak hanya menjadi sarana pembelajaran sejarah, tetapi juga membantu membentuk peserta didik yang berwawasan kebangsaan dan memiliki kesadaran sejarah yang kuat.\r\n', NULL, NULL),
(79, 3, 'Kamus Inggris-Indonesia', 46, 'John M.Echols dan Hassan Shadily', 7, 30, '2024', NULL, 'Buku Kamus Inggris–Indonesia yang disusun oleh John M. Echols dan Hassan Shadily serta diterbitkan oleh PT Gramedia Pustaka Utama merupakan kamus rujukan penting yang digunakan dalam pembelajaran bahasa Inggris di tingkat sekolah menengah. Kamus ini dirancang untuk membantu peserta didik dalam memahami dan menguasai kosakata bahasa Inggris secara lebih luas dan tepat, sehingga dapat menunjang keterampilan membaca, menulis, serta menerjemahkan teks berbahasa Inggris.\r\nKamus ini memuat ribuan entri kosakata lengkap dengan arti dalam bahasa Indonesia, contoh penggunaan kata, serta penjelasan makna dalam berbagai konteks. Penyusunan yang sistematis membuatnya mudah digunakan oleh pelajar dalam kegiatan belajar sehari-hari. Dengan kelengkapan isi dan keakuratan terjemahan, buku ini tidak hanya berfungsi sebagai alat bantu pembelajaran, tetapi juga sebagai referensi utama dalam meningkatkan kemampuan bahasa Inggris peserta didik di tingkat Kelas XI.', NULL, NULL),
(80, 2, 'Akidah Akhlak', 23, 'Nurul Hidayah', 6, 10, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas X Madrasah Aliyah yang disusun oleh Nurul Hidayah dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai keyakinan (akidah) dan pembentukan akhlak dalam ajaran Islam. Buku ini menjadi pedoman bagi peserta didik dalam memahami prinsip-prinsip keimanan sekaligus mengamalkannya dalam kehidupan sehari-hari.\r\n\r\nMateri yang disajikan mencakup rukun iman, yaitu iman kepada Allah, malaikat, kitab-kitab Allah, rasul, hari akhir, serta qada dan qadar. Selain itu, buku ini juga membahas pembinaan akhlak terpuji seperti jujur, amanah, disiplin, tanggung jawab, serta upaya menjauhi akhlak tercela dalam kehidupan pribadi maupun sosial. Seluruh materi disusun secara sistematis dan kontekstual sehingga mudah dipahami dan relevan dengan kehidupan peserta didik.\r\n\r\nMelalui berbagai kegiatan pembelajaran seperti diskusi, latihan, dan refleksi, peserta didik diarahkan tidak hanya memahami konsep keagamaan secara teoritis, tetapi juga mampu mengamalkannya dalam sikap dan perilaku sehari-hari. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, berakhlak mulia, serta bertanggung jawab dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(81, 3, 'Akidah Akhlak', 23, 'Sihabul Milahuddin', 6, 30, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas XI Madrasah Aliyah yang disusun oleh Sihabul Milahuddin dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep keimanan (akidah) dan pembentukan akhlak dalam ajaran Islam.\r\n\r\nBuku ini memuat materi lanjutan seperti penguatan rukun iman, pembahasan sifat-sifat Allah, iman kepada malaikat, kitab-kitab Allah, rasul, hari akhir, serta qada dan qadar. Selain itu, buku ini juga menekankan pembentukan akhlak terpuji seperti jujur, amanah, disiplin, tanggung jawab, serta sikap toleransi dalam kehidupan sosial, sekaligus menjauhi akhlak tercela yang dapat merusak hubungan antarindividu maupun masyarakat.\r\n\r\nPenyajian materi disusun secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan nilai-nilai akidah dan akhlak dengan kehidupan sehari-hari. Melalui berbagai kegiatan pembelajaran seperti diskusi, refleksi, dan latihan, peserta didik tidak hanya diarahkan untuk memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dalam perilaku nyata. Dengan pendekatan berbasis pembentukan karakter, buku ini berperan penting dalam membentuk pribadi muslim yang beriman, berakhlak mulia, dan bertanggung jawab dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(82, 2, 'AL Quran Hadist', 23, 'Syaifullah Amin', 6, 10, '2024', NULL, 'Buku Al-Qur’an Hadis untuk Kelas X Madrasah Aliyah yang disusun oleh Syaifullah Amin dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar kepada peserta didik mengenai Al-Qur’an dan hadis sebagai pedoman utama dalam ajaran Islam.\r\n\r\nBuku ini membahas berbagai materi penting seperti kedudukan dan fungsi Al-Qur’an dan hadis sebagai sumber hukum Islam, cara memahami kandungan ayat-ayat Al-Qur’an, serta peran hadis dalam menjelaskan dan memperkuat ajaran Al-Qur’an. Selain itu, peserta didik juga diajak untuk memahami nilai-nilai yang terkandung dalam Al-Qur’an dan hadis serta mengamalkannya dalam kehidupan sehari-hari.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga mudah dipahami dan relevan dengan kehidupan peserta didik. Melalui berbagai kegiatan pembelajaran seperti membaca, menghafal, diskusi, dan refleksi, peserta didik tidak hanya diarahkan untuk memahami konsep secara teoritis, tetapi juga mampu mengimplementasikannya dalam sikap dan perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini berfungsi tidak hanya sebagai sarana pembelajaran agama, tetapi juga sebagai media untuk membentuk pribadi muslim yang beriman, bertakwa, dan berakhlak mulia.\r\n', NULL, NULL),
(83, 3, 'AL Quran Hadist', 23, 'Pahruroji M. Bukhori', 6, 30, '2024', NULL, 'Buku Akidah Akhlak untuk Kelas XI Madrasah Aliyah yang disusun oleh Pahruroji dan M. Bukhori serta diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep akidah dan akhlak dalam ajaran Islam.\r\n\r\nBuku ini membahas berbagai materi lanjutan seperti penguatan rukun iman, sifat-sifat Allah SWT, iman kepada malaikat, kitab-kitab Allah, rasul, hari akhir, serta qada dan qadar. Selain itu, buku ini juga menekankan pembinaan akhlak terpuji seperti jujur, amanah, disiplin, tanggung jawab, serta sikap toleransi dalam kehidupan sosial, sekaligus menghindari akhlak tercela yang dapat merusak hubungan antarindividu maupun masyarakat.\r\n\r\nMateri disusun secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan nilai-nilai akidah dan akhlak dengan kehidupan sehari-hari. Melalui berbagai kegiatan pembelajaran seperti diskusi, refleksi, dan latihan, peserta didik tidak hanya diarahkan untuk memahami konsep secara teoritis, tetapi juga mampu mengamalkannya dalam perilaku nyata. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang beriman, berakhlak mulia, dan bertanggung jawab dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(84, 2, 'Bahasa Arab', 23, 'Muh. Ilyas', 6, 10, '2024', NULL, 'Buku Bahasa Arab untuk Kelas X Madrasah Aliyah yang disusun oleh Muh. Ilyas dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan dasar kemampuan berbahasa Arab kepada peserta didik.\r\n\r\nBuku ini mencakup berbagai materi penting seperti pengenalan kosakata (mufradat), struktur kalimat (qawa’id), percakapan sederhana (hiwar), membaca teks (qira’ah), serta keterampilan menulis (kitabah). Seluruh materi disusun secara bertahap dan sistematis sehingga mudah dipahami oleh peserta didik pada tingkat pemula.\r\n\r\nPenyajian materi dibuat secara kontekstual agar peserta didik mampu menggunakan bahasa Arab dalam situasi sehari-hari maupun memahami teks-teks sederhana yang berkaitan dengan keislaman. Melalui latihan, dialog, dan kegiatan pembelajaran interaktif, peserta didik diarahkan untuk mengembangkan kemampuan berbahasa secara aktif, baik lisan maupun tulisan. Dengan pendekatan komunikatif, buku ini tidak hanya menjadi sarana pembelajaran bahasa Arab, tetapi juga membantu peserta didik dalam memahami sumber ajaran Islam yang berbahasa Arab.\r\n', NULL, NULL),
(85, 3, 'Bahasa Arab', 23, 'Risna Rianti Sari, dan Hasyim Amirullah', 6, 30, '2024', NULL, 'Buku Bahasa Arab untuk Kelas XI Madrasah Aliyah yang disusun oleh Risna Rianti Sari dan Hasyim Amirullah serta diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa Arab peserta didik pada tingkat lanjutan.\r\n\r\nBuku ini memuat berbagai materi pembelajaran seperti pengembangan kosakata (mufradat), struktur kalimat (qawa’id), percakapan (hiwar), membaca teks (qira’ah), dan keterampilan menulis (kitabah) yang disusun dengan tingkat kesulitan yang lebih tinggi dibandingkan kelas sebelumnya.\r\n\r\nMateri disajikan secara sistematis dan komunikatif sehingga peserta didik dapat memahami serta menggunakan bahasa Arab dalam berbagai situasi kehidupan sehari-hari maupun dalam konteks keagamaan. Melalui latihan-latihan, dialog, dan aktivitas pembelajaran interaktif, peserta didik diarahkan untuk lebih aktif dalam mengasah kemampuan berbahasa, baik lisan maupun tulisan. Dengan pendekatan komunikatif, buku ini tidak hanya menjadi sarana pembelajaran bahasa Arab, tetapi juga membantu peserta didik dalam memahami teks-teks keislaman yang berbahasa Arab secara lebih mendalam.\r\n', NULL, NULL),
(86, 2, 'Fikih', 23, 'Muh. Asy ari', 6, 10, '2024', NULL, 'Buku Fikih untuk Kelas X Madrasah Aliyah yang disusun oleh Muh. Asy’ari dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai hukum-hukum Islam yang berkaitan dengan ibadah dan kehidupan sehari-hari.\r\n\r\nBuku ini membahas berbagai materi penting seperti konsep dasar fikih, sumber hukum Islam, thaharah (bersuci), salat, zakat, puasa, serta ketentuan-ketentuan ibadah lainnya yang menjadi pedoman dalam praktik keagamaan umat Islam. Seluruh materi disusun secara sistematis dan mudah dipahami sehingga peserta didik dapat mengaitkan antara teori fikih dengan praktik dalam kehidupan nyata.\r\n\r\nMelalui berbagai kegiatan pembelajaran seperti diskusi, latihan, dan praktik ibadah, peserta didik diarahkan tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya sesuai dengan tuntunan syariat Islam. Dengan pendekatan yang berorientasi pada pembentukan karakter religius, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang taat, disiplin, dan bertanggung jawab dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(87, 3, 'Fikih', 23, 'Atmo Prawiro', 6, 30, '2024', NULL, 'Buku Fikih untuk Kelas X Madrasah Aliyah yang disusun oleh Atmo Prawiro dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai hukum-hukum Islam yang berkaitan dengan ibadah dan kehidupan sehari-hari.\r\n\r\nBuku ini memuat berbagai materi penting seperti konsep dasar fikih, sumber hukum Islam, thaharah (bersuci), salat, zakat, puasa, serta berbagai ketentuan ibadah lainnya yang menjadi pedoman dalam praktik keagamaan umat Islam. Seluruh materi disusun secara sistematis sehingga mudah dipahami dan dapat diterapkan dalam kehidupan nyata.\r\n\r\nMelalui kegiatan pembelajaran seperti diskusi, latihan, dan praktik ibadah, peserta didik diarahkan tidak hanya memahami konsep secara teoritis, tetapi juga mampu mengamalkannya sesuai tuntunan syariat Islam. Dengan pendekatan yang berorientasi pada pembentukan karakter religius, buku ini tidak hanya berfungsi sebagai sarana pembelajaran agama, tetapi juga membantu membentuk pribadi muslim yang taat, disiplin, dan bertanggung jawab dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(88, 2, 'SKI', 23, 'Elfa Tsuroyya, S.Ag., M.Pd.I', 6, 10, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas X Madrasah Aliyah yang disusun oleh Elfa Tsuroyya, S.Ag., M.Pd.I. dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai perkembangan sejarah Islam sejak masa awal hingga perkembangan peradaban Islam di berbagai wilayah.\r\n\r\nBuku ini memuat berbagai materi penting seperti sejarah awal lahirnya Islam, perjuangan dakwah Rasulullah SAW di Makkah dan Madinah, masa Khulafaur Rasyidin, serta proses penyebaran Islam ke berbagai belahan dunia. Selain itu, buku ini juga menekankan nilai-nilai keteladanan seperti kejujuran, tanggung jawab, kerja keras, dan semangat perjuangan dalam menegakkan ajaran Islam.\r\n\r\nMateri disajikan secara sistematis dan kronologis sehingga peserta didik dapat memahami keterkaitan antarperistiwa sejarah serta mengambil hikmah dari setiap kejadian. Melalui kegiatan pembelajaran seperti diskusi, analisis, dan refleksi, peserta didik tidak hanya diarahkan untuk memahami fakta sejarah, tetapi juga mampu meneladani nilai-nilai positif dari perjalanan sejarah Islam. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran SKI, tetapi juga membantu membentuk pribadi yang berwawasan sejarah dan berakhlak mulia.\r\n', NULL, NULL),
(89, 3, 'SKI', 23, 'Moh. Sulaiman', 6, 30, '2024', NULL, 'Buku Sejarah Kebudayaan Islam (SKI) untuk Kelas XI Madrasah Aliyah yang disusun oleh Moh. Sulaiman dan diterbitkan oleh Kementerian Agama Republik Indonesia merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai perkembangan sejarah dan peradaban Islam pada masa pertengahan.\r\n\r\nBuku ini memuat berbagai materi penting seperti perkembangan Dinasti Umayyah dan Abbasiyah, kemajuan ilmu pengetahuan dalam dunia Islam, peran tokoh-tokoh ilmuwan Muslim, serta proses penyebaran Islam di berbagai wilayah dunia. Selain itu, buku ini juga menekankan nilai-nilai keteladanan seperti semangat keilmuan, kerja keras, kepemimpinan, dan kontribusi umat Islam dalam membangun peradaban.\r\n\r\nMateri disusun secara kronologis dan sistematis sehingga peserta didik dapat memahami hubungan antarperistiwa sejarah secara runtut. Melalui kegiatan pembelajaran seperti diskusi, analisis, dan refleksi, peserta didik tidak hanya diarahkan untuk memahami fakta sejarah, tetapi juga mampu mengambil nilai-nilai positif dari setiap peristiwa. Dengan pendekatan yang berorientasi pada pembentukan karakter, buku ini tidak hanya menjadi sarana pembelajaran SKI, tetapi juga membantu membentuk peserta didik yang berwawasan sejarah, berakhlak mulia, dan memiliki kecintaan terhadap peradaban Islam.\r\n', NULL, NULL),
(90, 7, 'Sosiologi', 37, 'Kun Mariati', 11, 25, '2024', NULL, 'Buku Sosiologi untuk Kelas XII yang disusun oleh Kun Maryati dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai dinamika sosial yang terjadi dalam kehidupan masyarakat yang lebih kompleks. Buku ini membahas berbagai materi penting seperti perubahan sosial, globalisasi, modernisasi, ketimpangan sosial, integrasi sosial, serta berbagai bentuk permasalahan sosial dan upaya penanganannya dalam konteks masyarakat Indonesia maupun global.\r\n\r\nMateri disajikan secara sistematis dengan mengaitkan konsep sosiologi dengan fenomena sosial aktual, sehingga peserta didik dapat memahami hubungan antara teori dan realitas kehidupan sehari-hari. Melalui berbagai studi kasus, analisis sosial, serta kegiatan diskusi, peserta didik diarahkan untuk mengembangkan kemampuan berpikir kritis, peka terhadap masalah sosial, dan mampu memberikan solusi yang rasional terhadap berbagai persoalan masyarakat.\r\n\r\nDengan pendekatan yang kontekstual dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sosiologi, tetapi juga membantu membentuk kesadaran sosial, sikap tanggung jawab, serta kemampuan beradaptasi dalam kehidupan bermasyarakat yang terus berkembang dan semakin kompleks.\r\n', NULL, NULL),
(91, 2, 'Prakarya', 17, 'Hendriana Werdaningsih, Albrta Haryudanti DKK', 3, 175, '2024', NULL, 'Buku Bahasa Indonesia untuk Kelas XII yang disusun oleh Maman Suryaman, Suherli, dan Istiqomah serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berbahasa dan bersastra peserta didik pada tingkat akhir pendidikan menengah.\r\n\r\nBuku ini memuat berbagai materi penting seperti teks editorial, artikel ilmiah, ceramah, teks proposal, resensi, serta karya sastra dalam berbagai bentuk. Selain itu, buku ini juga menekankan keterampilan membaca kritis, menulis efektif, berbicara, dan menyimak sebagai satu kesatuan kemampuan berbahasa yang utuh.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan pembelajaran dengan kehidupan sehari-hari maupun fenomena sosial yang ada di masyarakat. Melalui berbagai aktivitas pembelajaran seperti analisis teks, diskusi, dan praktik menulis, peserta didik diarahkan untuk berpikir kritis, kreatif, serta mampu menyampaikan gagasan secara logis dan terstruktur.\r\n\r\nDengan pendekatan berbasis teks dan penguatan literasi, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Indonesia, tetapi juga membantu membentuk peserta didik yang komunikatif, kritis, dan siap menghadapi tantangan akademik maupun kehidupan di masa depan.\r\n', NULL, NULL),
(92, 7, 'Bahasa Indonesia', 31, 'Maman Suriyaman, Suherli dan Istiqomah', 3, 30, '2024', NULL, 'Buku Bahasa Indonesia untuk Kelas XII yang disusun oleh Maman Suryaman, Suherli, dan Istiqomah serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berbahasa dan bersastra peserta didik pada tingkat akhir pendidikan menengah.\r\n\r\nBuku ini memuat berbagai materi penting seperti teks editorial, artikel ilmiah, ceramah, teks proposal, resensi, serta karya sastra dalam berbagai bentuk. Selain itu, buku ini juga menekankan keterampilan membaca kritis, menulis efektif, berbicara, dan menyimak sebagai satu kesatuan kemampuan berbahasa yang utuh.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan pembelajaran dengan kehidupan sehari-hari maupun fenomena sosial yang ada di masyarakat. Melalui berbagai aktivitas pembelajaran seperti analisis teks, diskusi, dan praktik menulis, peserta didik diarahkan untuk berpikir kritis, kreatif, serta mampu menyampaikan gagasan secara logis dan terstruktur.\r\n\r\nDengan pendekatan berbasis teks dan penguatan literasi, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Indonesia, tetapi juga membantu membentuk peserta didik yang komunikatif, kritis, dan siap menghadapi tantangan akademik maupun kehidupan di masa depan.\r\n', NULL, NULL),
(93, 3, 'Bahasa Inggris', 46, 'Makhruk Bashir', 3, 100, '2024', NULL, 'Buku Bahasa Inggris untuk Kelas XI yang disusun oleh Makhruk Bashir dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa Inggris peserta didik pada tingkat menengah.\r\n\r\nBuku ini memuat berbagai materi penting seperti keterampilan membaca (reading), menulis (writing), mendengarkan (listening), dan berbicara (speaking) yang disusun secara terpadu. Selain itu, buku ini juga mencakup berbagai jenis teks seperti descriptive text, recount text, narrative text, procedure text, dan report text yang bertujuan untuk melatih kemampuan memahami dan menghasilkan teks berbahasa Inggris dengan baik.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan pembelajaran dengan kehidupan sehari-hari. Melalui berbagai aktivitas seperti latihan soal, percakapan, dan proyek bahasa, peserta didik diarahkan untuk lebih aktif menggunakan bahasa Inggris dalam komunikasi nyata.\r\n\r\nDengan pendekatan komunikatif dan berbasis keterampilan, buku ini tidak hanya berfungsi sebagai sarana pembelajaran bahasa Inggris, tetapi juga membantu membentuk peserta didik yang mampu berkomunikasi secara efektif dalam bahasa Inggris baik secara lisan maupun tulisan.\r\n', NULL, NULL),
(94, 7, 'Bahasa Inggris', 47, 'Utami Widyati, Zulyati Rohmah dan Furaidah', 3, 50, '2024', NULL, 'Buku Bahasa Inggris untuk Kelas XII yang disusun oleh Utami Widyati, Zulyati Rohmah, dan Furaidah serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa Inggris peserta didik pada tingkat akhir pendidikan menengah.\r\n\r\nBuku ini mencakup berbagai keterampilan berbahasa seperti reading, writing, listening, dan speaking yang disajikan secara terpadu. Selain itu, materi pembelajaran meliputi berbagai jenis teks seperti narrative text, report text, analytical exposition, hortatory exposition, dan review text yang bertujuan untuk memperkuat kemampuan peserta didik dalam memahami serta menghasilkan teks berbahasa Inggris secara baik dan benar.\r\n\r\nPenyajian materi dilakukan secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan pembelajaran dengan situasi nyata dalam kehidupan sehari-hari. Melalui berbagai aktivitas seperti latihan soal, diskusi, presentasi, dan proyek bahasa, peserta didik diarahkan untuk lebih aktif dan percaya diri dalam menggunakan bahasa Inggris.\r\n\r\nDengan pendekatan komunikatif dan berbasis keterampilan, buku ini tidak hanya berfungsi sebagai sarana pembelajaran bahasa Inggris, tetapi juga membantu membentuk peserta didik yang mampu berkomunikasi secara efektif dalam bahasa Inggris, baik secara lisan maupun tulisan.\r\n', NULL, NULL),
(95, 7, 'Matematika Peminatan', 41, 'Drs. B.K. Noormandiri, M.Pd', 11, 10, '2024', NULL, 'Buku Matematika Peminatan untuk Kelas XII yang disusun oleh Drs. B.K. Noormandiri, M.Pd. dan diterbitkan oleh PT Erlangga merupakan sumber pembelajaran yang dirancang untuk memperdalam penguasaan konsep matematika lanjutan bagi peserta didik pada jenjang pendidikan menengah atas, khususnya pada peminatan MIPA.\r\n\r\nBuku ini membahas berbagai materi penting seperti limit fungsi, turunan (diferensial), integral, matriks lanjutan, program linear, serta pengenalan konsep-konsep matematika yang lebih kompleks sesuai dengan tingkat pemahaman kelas XII. Materi disusun secara sistematis dan bertahap agar peserta didik dapat memahami konsep dasar hingga penerapan dalam penyelesaian masalah.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan berbagai contoh soal, latihan, dan pembahasan yang bertujuan untuk melatih kemampuan berpikir logis, analitis, dan sistematis. Pendekatan pembelajaran yang digunakan menekankan pada pemecahan masalah (problem solving) sehingga peserta didik mampu mengaplikasikan konsep matematika dalam berbagai situasi.\r\n\r\nDengan struktur yang terarah dan materi yang mendalam, buku ini tidak hanya berfungsi sebagai sarana pembelajaran matematika peminatan, tetapi juga membantu membentuk kemampuan berpikir kritis dan kesiapan peserta didik dalam menghadapi pendidikan tinggi.\r\n', NULL, NULL),
(96, 7, 'Matematika', 41, 'Abdur Rahman As ari, Tjang Daniel Chandra DKK', 3, 70, '2024', NULL, 'Buku Matematika untuk Kelas XII yang disusun oleh Abdur Rahman As’ari, Tjang Daniel Chandra, dan tim (dkk) serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berpikir logis, sistematis, dan analitis peserta didik pada tingkat pendidikan menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti limit fungsi, turunan, integral, statistika, peluang, serta penerapan konsep matematika dalam pemecahan masalah kontekstual. Materi disusun secara sistematis dan bertahap agar peserta didik dapat memahami konsep dari dasar hingga penerapannya dalam berbagai situasi.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan contoh soal, latihan, dan aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis serta mampu menyelesaikan masalah secara mandiri maupun kelompok. Pendekatan yang digunakan menekankan pada pembelajaran aktif dan berbasis masalah (problem-based learning) sehingga peserta didik dapat mengaitkan konsep matematika dengan kehidupan sehari-hari.\r\n\r\nDengan pendekatan yang kontekstual dan komprehensif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran matematika, tetapi juga membantu membentuk kemampuan berpikir kritis, kreatif, dan siap menghadapi tantangan pendidikan lanjutan.\r\n', NULL, NULL),
(97, 2, 'PKN', 16, 'Hatim Gazali, Abdul Waidi, Ali Usman, DKK', 3, 30, '2024', NULL, 'Buku Pendidikan Pancasila dan Kewarganegaraan (PPKn) untuk Kelas X yang disusun oleh Hatim Gazali, Abdul Waidi, Ali Usman, dan tim (dkk) serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk menanamkan nilai-nilai kebangsaan, karakter, dan kewarganegaraan kepada peserta didik.\r\n\r\nBuku ini memuat berbagai materi penting seperti Pancasila sebagai dasar negara dan ideologi bangsa, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, sistem pemerintahan Indonesia, hak dan kewajiban warga negara, serta pentingnya menjaga persatuan dan kesatuan dalam keberagaman masyarakat Indonesia. Selain itu, buku ini juga membahas nilai-nilai demokrasi, hukum, dan konstitusi dalam kehidupan berbangsa dan bernegara.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat mengaitkan konsep kewarganegaraan dengan kehidupan sehari-hari. Melalui berbagai kegiatan pembelajaran seperti diskusi, studi kasus, dan refleksi, peserta didik diarahkan untuk berpikir kritis, memiliki sikap nasionalis, serta bertanggung jawab sebagai warga negara yang baik.\r\n\r\nDengan pendekatan berbasis karakter dan kontekstual, buku ini tidak hanya berfungsi sebagai sarana pembelajaran PPKn, tetapi juga membantu membentuk peserta didik yang berintegritas, demokratis, dan cinta tanah air.\r\n', NULL, NULL),
(98, 2, 'PJOK', 5, 'Tim media mandiri', 10, 30, '2024', NULL, 'Buku Pendidikan Jasmani, Olahraga, dan Kesehatan (PJOK) untuk Kelas X yang disusun oleh Tim Media Mandiri dan diterbitkan oleh Media Mandiri merupakan sumber pembelajaran yang dirancang untuk mengembangkan pengetahuan, keterampilan, dan sikap peserta didik dalam bidang olahraga dan kesehatan.\r\n\r\nBuku ini memuat berbagai materi penting seperti permainan bola besar dan bola kecil, atletik, senam, aktivitas kebugaran jasmani, bela diri, serta pemahaman tentang kesehatan tubuh dan pola hidup sehat. Setiap materi disusun secara sistematis agar peserta didik tidak hanya memahami teori, tetapi juga mampu melakukan praktik olahraga dengan benar dan aman.\r\n\r\nSelain aspek keterampilan fisik, buku ini juga menekankan pentingnya sportivitas, kerja sama, disiplin, dan gaya hidup sehat dalam kehidupan sehari-hari. Melalui kegiatan pembelajaran yang bersifat praktik, latihan fisik, dan evaluasi kebugaran, peserta didik diarahkan untuk menjaga kesehatan tubuh sekaligus mengembangkan kemampuan motorik.\r\n\r\nDengan pendekatan yang aktif dan aplikatif, buku ini tidak hanya berfungsi sebagai sarana pembelajaran PJOK, tetapi juga membantu membentuk peserta didik yang sehat jasmani, disiplin, dan memiliki karakter sportif.\r\n', NULL, NULL),
(99, 2, 'Sejarah Peminatan', 14, 'Martini  Sagitry', 9, 25, '2024', NULL, 'Buku Sejarah Peminatan untuk Kelas X yang disusun oleh Martini Sagitry dan diterbitkan oleh Yudhistira merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai sejarah sebagai ilmu dan perkembangan peradaban manusia secara lebih khusus dan analitis.\r\n\r\nBuku ini memuat berbagai materi penting seperti pengertian sejarah sebagai ilmu, konsep waktu dalam sejarah, metode penelitian sejarah, sumber-sumber sejarah, serta perkembangan peradaban awal manusia di dunia dan Nusantara. Materi disusun secara sistematis agar peserta didik mampu memahami proses sejarah tidak hanya sebagai rangkaian peristiwa, tetapi juga sebagai kajian ilmiah yang memiliki sebab-akibat dan keterkaitan antar peristiwa.\r\n\r\nSelain itu, buku ini juga dilengkapi dengan aktivitas pembelajaran seperti analisis sumber sejarah, diskusi, dan latihan soal yang bertujuan untuk melatih kemampuan berpikir kritis, kronologis, dan analitis peserta didik. Pendekatan yang digunakan menekankan pada pemahaman konsep dan keterampilan berpikir sejarah (historical thinking skills).\r\n\r\nDengan demikian, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sejarah peminatan, tetapi juga membantu membentuk peserta didik yang memiliki kesadaran sejarah, kemampuan analisis yang baik, serta wawasan kebangsaan yang lebih luas.\r\n', NULL, NULL),
(100, 2, 'Informatika', 12, 'Mushthofa, Wahyuno, Auzi Asfarian, DKK', 3, 1, '2024', NULL, 'Buku Informatika untuk Kelas X yang disusun oleh Mushthofa, Wahyuno, Auzi Asfarian, dan tim (dkk) serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengenalkan konsep dasar informatika kepada peserta didik pada jenjang pendidikan menengah.\r\n\r\nBuku ini membahas berbagai materi penting seperti berpikir komputasional, sistem komputer, jaringan komputer dan internet, data dan representasinya, algoritma dan pemrograman dasar, serta dampak sosial informatika dalam kehidupan sehari-hari. Materi disusun secara sistematis agar peserta didik dapat memahami konsep teknologi informasi secara menyeluruh.\r\n\r\nSelain teori, buku ini juga dilengkapi dengan aktivitas praktik seperti penyusunan algoritma sederhana, penggunaan aplikasi digital, serta eksplorasi teknologi informasi untuk melatih keterampilan problem solving dan berpikir logis. Pendekatan pembelajaran berbasis praktik dan eksplorasi membuat peserta didik lebih aktif dalam memahami materi.\r\n\r\nDengan pendekatan yang kontekstual dan berbasis keterampilan abad 21, buku ini tidak hanya berfungsi sebagai sarana pembelajaran informatika, tetapi juga membantu membentuk peserta didik yang melek teknologi, kreatif, dan siap menghadapi perkembangan dunia digital.\r\n', NULL, NULL),
(101, 2, 'Cerdas Berbahasa Indonesia', 4, 'Heny Marwati', 3, 30, '2024', NULL, 'Buku *Cerdas Bahasa Indonesia* untuk Kelas X yang disusun oleh Heny Marwati dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa dan bersastra peserta didik pada tingkat sekolah menengah.\r\n\r\nBuku ini memuat berbagai materi penting seperti pemahaman teks laporan, teks eksposisi, teks prosedur, teks anekdot, serta berbagai jenis teks lainnya yang digunakan dalam pembelajaran Bahasa Indonesia. Selain itu, buku ini juga mengembangkan keterampilan membaca, menulis, menyimak, dan berbicara secara terpadu agar peserta didik mampu berkomunikasi secara efektif.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga mudah dipahami serta relevan dengan kehidupan sehari-hari. Melalui berbagai latihan, aktivitas menulis, diskusi, dan analisis teks, peserta didik diarahkan untuk berpikir kritis, kreatif, serta mampu mengungkapkan gagasan dengan baik dan terstruktur.\r\n\r\nDengan pendekatan berbasis literasi dan keterampilan berbahasa, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Indonesia, tetapi juga membantu membentuk peserta didik yang komunikatif, kritis, dan berwawasan luas.\r\n', NULL, NULL),
(102, 3, 'Cerdas Berbahasa Indonesia', 30, 'Heny Marwati', 3, 30, '2024', NULL, 'Buku *Cerdas Bahasa Indonesia* untuk Kelas XI yang disusun oleh Heny Marwati dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa dan bersastra peserta didik pada tingkat menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti teks prosedur kompleks, teks eksplanasi, teks ceramah, teks cerpen, teks proposal, serta berbagai bentuk karya tulis lainnya. Selain itu, buku ini juga menekankan penguatan keterampilan membaca, menulis, menyimak, dan berbicara secara terpadu dalam berbagai konteks komunikasi.\r\n\r\nMateri disajikan secara sistematis dan kontekstual sehingga peserta didik dapat menghubungkan pembelajaran dengan kehidupan sehari-hari. Melalui berbagai aktivitas seperti analisis teks, diskusi, presentasi, dan penulisan karya ilmiah sederhana, peserta didik diarahkan untuk berpikir kritis, kreatif, dan mampu menyampaikan gagasan secara logis serta terstruktur.\r\n\r\nDengan pendekatan berbasis literasi dan penguatan keterampilan berbahasa, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Indonesia, tetapi juga membantu membentuk peserta didik yang komunikatif, kritis, dan siap menghadapi tantangan akademik maupun kehidupan di masa depan.\r\n', NULL, NULL),
(103, 2, 'Matematika', 9, 'Dicky Susanto, Theja Kurniawan, Savitri K, DKK', 3, 30, '2024', NULL, 'Buku Matematika untuk Kelas X yang disusun oleh Dicky Susanto, Theja Kurniawan, Savitri K., dan tim (dkk) serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berpikir logis, analitis, dan sistematis peserta didik pada jenjang sekolah menengah.\r\n\r\nBuku ini memuat berbagai materi penting seperti bilangan real, persamaan dan pertidaksamaan, fungsi, sistem persamaan linear, trigonometri dasar, serta pengenalan statistika dan peluang. Seluruh materi disusun secara bertahap agar peserta didik dapat memahami konsep dari dasar hingga penerapannya dalam pemecahan masalah.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan contoh soal, latihan, dan aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis serta mampu menyelesaikan permasalahan matematika secara mandiri maupun berkelompok. Pendekatan pembelajaran yang digunakan menekankan pada pemahaman konsep dan penerapan dalam kehidupan sehari-hari.\r\n\r\nDengan pendekatan yang sistematis dan kontekstual, buku ini tidak hanya berfungsi sebagai sarana pembelajaran matematika, tetapi juga membantu membentuk kemampuan berpikir kritis, kreatif, dan siap menghadapi tantangan pembelajaran di jenjang berikutnya.\r\n', NULL, NULL),
(104, 3, 'Matematika', 40, 'Dicky Susanto, Savitri K, Sihombing, DKK', 3, 30, '2025', NULL, 'Buku Matematika untuk Kelas XI yang disusun oleh Dicky Susanto, Savitri K., Sihombing, dan tim (dkk) serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berpikir logis, analitis, dan sistematis peserta didik pada jenjang sekolah menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti fungsi dan grafik fungsi, persamaan dan pertidaksamaan, trigonometri lanjutan, limit fungsi, statistika, serta peluang. Materi disusun secara sistematis dan bertahap agar peserta didik dapat memahami konsep matematika dari dasar hingga penerapannya dalam pemecahan masalah yang lebih kompleks.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan contoh soal, latihan, serta aktivitas pembelajaran yang mendorong peserta didik untuk berpikir kritis, kreatif, dan mampu menyelesaikan masalah secara mandiri maupun kelompok. Pendekatan pembelajaran yang digunakan menekankan pada pemahaman konsep, penalaran, dan penerapan matematika dalam kehidupan sehari-hari.\r\n\r\nDengan pendekatan yang kontekstual dan terstruktur, buku ini tidak hanya berfungsi sebagai sarana pembelajaran matematika, tetapi juga membantu membentuk kemampuan berpikir tingkat tinggi serta kesiapan peserta didik dalam menghadapi pembelajaran di jenjang yang lebih lanjut.\r\n', NULL, NULL),
(105, 3, 'Biologi', 24, 'Dewi Safitry', 3, 30, '2025', NULL, 'Buku Biologi untuk Kelas XI yang disusun oleh Dewi Safitry dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam mengenai konsep-konsep biologi pada tingkat menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti struktur dan fungsi sel, jaringan pada makhluk hidup, sistem organ pada manusia, sistem pernapasan, sistem pencernaan, sistem peredaran darah, serta sistem ekskresi. Selain itu, juga dibahas materi mengenai keanekaragaman hayati, ekosistem, serta hubungan antara makhluk hidup dan lingkungannya.\r\n\r\nMateri disusun secara sistematis dan bertahap sehingga peserta didik dapat memahami konsep dasar biologi hingga penerapannya dalam kehidupan sehari-hari. Buku ini juga dilengkapi dengan kegiatan praktikum, pengamatan, dan latihan soal yang bertujuan untuk mengembangkan keterampilan ilmiah, kemampuan berpikir kritis, serta rasa ingin tahu peserta didik.\r\n\r\nDengan pendekatan kontekstual dan berbasis sains, buku ini tidak hanya berfungsi sebagai sarana pembelajaran biologi, tetapi juga membantu membentuk peserta didik yang memiliki kesadaran terhadap pentingnya ilmu pengetahuan dan kelestarian lingkungan.\r\n', NULL, NULL),
(106, 3, 'Kimia', 28, 'Sri Utami', 3, 30, '2025', NULL, 'Buku Kimia untuk Kelas XI yang disusun oleh Sri Utami dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep-konsep kimia pada tingkat menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti struktur atom lanjutan, ikatan kimia, stoikiometri, larutan elektrolit dan non-elektrolit, kesetimbangan kimia, laju reaksi, serta termokimia. Seluruh materi disusun secara sistematis agar peserta didik dapat memahami hubungan antara konsep teori kimia dengan fenomena yang terjadi dalam kehidupan sehari-hari.\r\n\r\nSelain penyajian materi, buku ini juga dilengkapi dengan contoh soal, latihan, serta kegiatan praktikum yang bertujuan untuk mengembangkan kemampuan berpikir ilmiah, analitis, dan kritis. Melalui pendekatan pembelajaran berbasis eksperimen, peserta didik diarahkan untuk mampu mengamati, menganalisis, dan menarik kesimpulan dari berbagai percobaan kimia.\r\n\r\nDengan pendekatan yang kontekstual dan berbasis sains, buku ini tidak hanya berfungsi sebagai sarana pembelajaran kimia, tetapi juga membantu membentuk peserta didik yang memiliki kemampuan berpikir ilmiah serta kesadaran terhadap penerapan kimia dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(107, 3, 'Fisika', 26, 'Bambang Ruwanto', 3, 30, '2025', NULL, 'Buku Fisika untuk Kelas XI yang disusun oleh Bambang Ruwanto dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman mendalam mengenai konsep-konsep dasar dan lanjutan dalam ilmu fisika pada jenjang sekolah menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti gerak lurus dan gerak melingkar, hukum Newton tentang gerak, usaha dan energi, momentum dan impuls, getaran dan gelombang, serta fluida. Materi disusun secara sistematis agar peserta didik dapat memahami hubungan antara konsep fisika dan fenomena yang terjadi dalam kehidupan sehari-hari.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan contoh soal, latihan, serta kegiatan eksperimen atau praktikum yang bertujuan untuk mengembangkan keterampilan berpikir ilmiah, analitis, dan kritis. Pendekatan pembelajaran berbasis eksperimen membantu peserta didik dalam mengamati, menganalisis, dan menarik kesimpulan dari berbagai gejala fisika.\r\n\r\nDengan pendekatan yang kontekstual dan berbasis sains, buku ini tidak hanya berfungsi sebagai sarana pembelajaran fisika, tetapi juga membantu membentuk peserta didik yang memiliki kemampuan berpikir logis serta pemahaman yang kuat terhadap prinsip-prinsip fisika dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(108, 2, 'Bahasa Inggris', 13, 'Utami Widiati, Zuliati Rohmah, Furaidah', 3, 30, '2025', NULL, 'Buku Bahasa Inggris untuk Kelas X yang disusun oleh Utami Widiati, Zuliati Rohmah, dan Furaidah serta diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk mengembangkan kemampuan berbahasa Inggris peserta didik pada tingkat sekolah menengah.\r\n\r\nBuku ini mencakup empat keterampilan utama dalam berbahasa, yaitu listening (menyimak), speaking (berbicara), reading (membaca), dan writing (menulis) yang disajikan secara terpadu. Selain itu, buku ini juga memuat berbagai jenis teks seperti descriptive text, recount text, narrative text, procedure text, dan report text yang bertujuan untuk melatih pemahaman serta kemampuan peserta didik dalam menggunakan bahasa Inggris secara baik dan benar.\r\n\r\nMateri disusun secara sistematis dan kontekstual sehingga mudah dipahami serta relevan dengan kehidupan sehari-hari peserta didik. Melalui berbagai latihan, percakapan, tugas proyek, dan aktivitas komunikasi, peserta didik diarahkan untuk lebih aktif dan percaya diri dalam menggunakan bahasa Inggris.\r\n\r\nDengan pendekatan komunikatif dan berbasis keterampilan, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Inggris, tetapi juga membantu membentuk peserta didik yang mampu berkomunikasi secara efektif dalam bahasa Inggris, baik secara lisan maupun tulisan.\r\n', NULL, NULL),
(109, 3, 'Bahasa Inggris', 46, 'Zuliati Rohmah', 3, 30, '2025', NULL, 'Buku Bahasa Inggris untuk Kelas XI yang disusun oleh Zuliati Rohmah dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk meningkatkan kemampuan berbahasa Inggris peserta didik pada tingkat menengah atas.\r\n\r\nBuku ini mencakup empat keterampilan berbahasa utama, yaitu listening (menyimak), speaking (berbicara), reading (membaca), dan writing (menulis) yang disajikan secara terpadu. Selain itu, materi pembelajaran juga meliputi berbagai jenis teks seperti narrative text, recount text, procedure text, report text, dan analytical exposition yang bertujuan untuk melatih kemampuan peserta didik dalam memahami dan menghasilkan teks berbahasa Inggris dengan baik dan benar.\r\n\r\nMateri disusun secara sistematis dan kontekstual sehingga mudah dipahami serta relevan dengan kehidupan sehari-hari peserta didik. Melalui berbagai latihan, dialog, diskusi, dan tugas proyek, peserta didik diarahkan untuk aktif menggunakan bahasa Inggris dalam berbagai situasi komunikasi.\r\n\r\nDengan pendekatan komunikatif dan berbasis keterampilan, buku ini tidak hanya berfungsi sebagai sarana pembelajaran Bahasa Inggris, tetapi juga membantu membentuk peserta didik yang mampu berkomunikasi secara efektif, baik secara lisan maupun tulisan.\r\n', NULL, NULL),
(110, 2, 'Sejarah', 60, 'Sari Oktafiana', 3, 30, '2025', NULL, 'Buku Sejarah untuk Kelas X yang disusun oleh Sari Oktafiana dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai konsep dan ruang lingkup ilmu sejarah kepada peserta didik pada jenjang sekolah menengah.\r\n\r\nBuku ini membahas berbagai materi penting seperti pengertian sejarah sebagai ilmu, konsep waktu dalam sejarah, kronologi dan periodisasi, sumber-sumber sejarah, serta perkembangan peradaban awal manusia di dunia dan di Indonesia. Materi disusun secara sistematis agar peserta didik mampu memahami sejarah tidak hanya sebagai kumpulan peristiwa, tetapi juga sebagai proses yang memiliki sebab-akibat dan keterkaitan antar kejadian.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan aktivitas pembelajaran seperti analisis sumber sejarah, diskusi, dan latihan soal yang bertujuan untuk melatih kemampuan berpikir kritis, kronologis, dan analitis peserta didik. Pendekatan yang digunakan menekankan pada keterampilan berpikir sejarah (historical thinking skills) serta pemahaman konsep secara mendalam.\r\n\r\nDengan pendekatan yang kontekstual dan ilmiah, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sejarah, tetapi juga membantu membentuk peserta didik yang memiliki kesadaran sejarah, wawasan kebangsaan, serta kemampuan analisis yang baik terhadap peristiwa masa lalu.\r\n', NULL, NULL);
INSERT INTO `buku` (`id`, `kelas_id`, `judul`, `rak_buku_id`, `pengarang`, `penerbit_id`, `jumlah`, `tahun`, `cover`, `deskripsi`, `created_at`, `updated_at`) VALUES
(111, 3, 'Sejarah', 61, 'Sari Oktafiana', 3, 30, '2025', NULL, 'Buku Sejarah untuk Kelas XI yang disusun oleh Sari Oktafiana dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai perkembangan sejarah dunia dan Indonesia pada masa modern.\r\n\r\nBuku ini memuat berbagai materi penting seperti perkembangan kolonialisme dan imperialisme, pergerakan nasional di Indonesia, revolusi besar dunia, serta perubahan sosial, politik, dan ekonomi yang terjadi pada masa modern. Materi disusun secara sistematis agar peserta didik dapat memahami keterkaitan antara peristiwa sejarah secara kronologis dan kausalitasnya.\r\n\r\nSelain itu, buku ini juga dilengkapi dengan aktivitas pembelajaran seperti analisis sumber sejarah, diskusi, dan kajian peristiwa yang bertujuan untuk melatih kemampuan berpikir kritis, analitis, dan historis peserta didik. Pendekatan yang digunakan menekankan pada pengembangan keterampilan berpikir sejarah (historical thinking skills) serta pemahaman konteks sejarah secara mendalam.\r\n\r\nDengan pendekatan yang kontekstual dan ilmiah, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sejarah, tetapi juga membantu membentuk peserta didik yang memiliki wawasan kebangsaan, kesadaran sejarah, serta kemampuan analisis yang baik terhadap dinamika perubahan zaman.\r\n', NULL, NULL),
(112, 3, 'Sosiologi', 36, 'Kun Mariati', 3, 30, '2025', NULL, 'Buku Sosiologi untuk Kelas XI yang disusun oleh Kun Maryati dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar mengenai konsep-konsep sosiologi pada tingkat sekolah menengah atas.\r\n\r\nBuku ini membahas berbagai materi penting seperti individu dan masyarakat, interaksi sosial, nilai dan norma sosial, sosialisasi, penyimpangan sosial, serta pengendalian sosial. Materi disusun secara sistematis agar peserta didik dapat memahami hubungan antara individu, kelompok, dan struktur sosial dalam kehidupan masyarakat.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan berbagai contoh kasus sosial, aktivitas diskusi, serta latihan soal yang bertujuan untuk mengembangkan kemampuan berpikir kritis, analitis, dan peka terhadap fenomena sosial di sekitar peserta didik. Pendekatan pembelajaran yang digunakan menekankan pada keterkaitan antara konsep sosiologi dengan realitas kehidupan sehari-hari.\r\n\r\nDengan pendekatan yang kontekstual dan berbasis pemecahan masalah sosial, buku ini tidak hanya berfungsi sebagai sarana pembelajaran sosiologi, tetapi juga membantu membentuk peserta didik yang memiliki kesadaran sosial, sikap kritis, dan kemampuan beradaptasi dalam kehidupan bermasyarakat.\r\n', NULL, NULL),
(113, 3, 'Ekonomi', 50, 'yeni fitriani', 3, 30, '2025', NULL, 'Buku Ekonomi untuk Kelas XI yang disusun oleh Yeni Fitriani dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memberikan pemahaman dasar dan lanjutan mengenai konsep ekonomi pada tingkat sekolah menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti konsep dasar ilmu ekonomi, permintaan dan penawaran, pasar, struktur pasar, pendapatan nasional, inflasi, serta kebijakan ekonomi. Materi disusun secara sistematis agar peserta didik dapat memahami keterkaitan antara teori ekonomi dan fenomena yang terjadi dalam kehidupan sehari-hari.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan contoh soal, latihan, serta studi kasus ekonomi yang bertujuan untuk melatih kemampuan berpikir kritis, analitis, dan logis peserta didik dalam memahami permasalahan ekonomi. Pendekatan pembelajaran yang digunakan menekankan pada pemahaman konsep dan penerapan dalam konteks nyata.\r\n\r\nDengan pendekatan yang kontekstual dan berbasis pemecahan masalah, buku ini tidak hanya berfungsi sebagai sarana pembelajaran ekonomi, tetapi juga membantu membentuk peserta didik yang memiliki pemahaman ekonomi yang baik serta mampu mengambil keputusan secara rasional dalam kehidupan sehari-hari.\r\n', NULL, NULL),
(114, 3, 'Informatika', 44, 'Inggriani', 3, 1, '2025', NULL, 'Buku Informatika untuk Kelas XI yang disusun oleh Inggriani Liem dan diterbitkan oleh Kementerian Pendidikan dan Kebudayaan merupakan sumber pembelajaran yang dirancang untuk memperdalam pemahaman peserta didik mengenai konsep-konsep dasar dan lanjutan dalam bidang informatika pada tingkat sekolah menengah atas.\r\n\r\nBuku ini memuat berbagai materi penting seperti berpikir komputasional lanjutan, struktur data sederhana, algoritma dan pemrograman, sistem komputer, jaringan komputer, keamanan digital, serta pemanfaatan teknologi informasi dalam kehidupan sehari-hari. Materi disusun secara sistematis agar peserta didik mampu memahami konsep informatika secara lebih mendalam dan terstruktur.\r\n\r\nSelain penyajian teori, buku ini juga dilengkapi dengan kegiatan praktik seperti penyusunan algoritma, pemrograman dasar, analisis data sederhana, serta eksplorasi aplikasi digital. Hal ini bertujuan untuk mengembangkan keterampilan problem solving, logika, dan kreativitas peserta didik dalam bidang teknologi informasi.\r\n\r\nDengan pendekatan berbasis keterampilan abad 21, buku ini tidak hanya berfungsi sebagai sarana pembelajaran informatika, tetapi juga membantu membentuk peserta didik yang melek teknologi, adaptif, dan siap menghadapi perkembangan dunia digital yang terus berubah.\r\n', NULL, NULL),
(115, 7, 'Kamus Inggris-Indonesia', 47, 'John M.Echols dan Hassan Shadily', 7, 30, '2025', NULL, 'Kamus Bahasa Inggris–Indonesia yang disusun oleh John M. Echols dan Hassan Shadily serta diterbitkan oleh Gramedia merupakan salah satu kamus rujukan penting yang digunakan dalam pembelajaran bahasa Inggris di tingkat sekolah menengah hingga perguruan tinggi.\r\n\r\nKamus ini berisi kumpulan kosakata bahasa Inggris beserta terjemahannya dalam bahasa Indonesia yang disusun secara alfabetis untuk memudahkan pencarian. Selain arti kata, kamus ini juga memberikan contoh penggunaan kata dalam kalimat sehingga membantu pengguna memahami konteks pemakaian bahasa Inggris secara lebih tepat.\r\n\r\nKamus ini sangat bermanfaat bagi peserta didik dalam meningkatkan penguasaan kosakata (vocabulary), memahami teks bahasa Inggris, serta mendukung keterampilan membaca, menulis, dan menerjemahkan. Dengan kelengkapan dan keakuratan isinya, kamus ini menjadi salah satu referensi utama dalam pembelajaran bahasa Inggris di Indonesia.\r\n\r\nSebagai sumber belajar, kamus ini tidak hanya membantu dalam penerjemahan kata, tetapi juga mendukung pengembangan kemampuan bahasa secara menyeluruh, terutama dalam memahami makna kata sesuai konteks penggunaannya.\r\n', NULL, NULL);
